                            <Database size={10} />
                            <span>Nguồn: </span>
                            <span className="font-bold text-white">
                                {formData.tableDisplayName || formData.tableName || 'WMS Service'}
                            </span>
                        </div>
                    </div>
                    <button onClick={() => {
                        setIsEditing(false);
                        setSelectedParcel(null);
                        popupElement.current!.style.display = 'none';
                        if(highlightLayer.current) highlightLayer.current.getSource().clear();
                        popupOverlay.current.setPosition(undefined); 
                    }} className="hover:bg-white/20 rounded p-1 transition-colors"><X size={18} /></button>
                </div>

                <div className="p-4 space-y-4">
                     {/* Info Cards */}
                     <div className="flex gap-3">
                         <div className="flex-1 bg-gray-50 border border-gray-200 rounded-lg p-2.5 text-center shadow-sm">
                             <div className="text-[10px] text-gray-500 font-bold uppercase tracking-wider mb-1">Tờ bản đồ</div>
                             <div className="text-2xl font-extrabold text-blue-600">{formData.so_to || '?'}</div>
                         </div>
                         <div className="flex-1 bg-gray-50 border border-gray-200 rounded-lg p-2.5 text-center shadow-sm">
                             <div className="text-[10px] text-gray-500 font-bold uppercase tracking-wider mb-1">Số thửa</div>
                             <div className="text-2xl font-extrabold text-blue-600">{formData.so_thua || '?'}</div>
                         </div>
                     </div>

                     <div className="space-y-3">
                         <div className="flex items-start gap-3 p-2 hover:bg-gray-50 rounded transition-colors">
                             <div className="bg-blue-100 p-2 rounded-full text-blue-600 mt-0.5"><UserIcon size={16}/></div>
                             <div className="flex-1">
                                 <label className="text-xs text-gray-500 font-bold uppercase block mb-0.5">Chủ sở hữu</label>
                                 <div className="text-sm font-bold text-gray-900">{formData.ownerName || 'Chưa xác định'}</div>
                             </div>
                         </div>

                         <div className="flex items-start gap-3 p-2 hover:bg-gray-50 rounded transition-colors">
                             <div className="bg-orange-100 p-2 rounded-full text-orange-600 mt-0.5"><MapPin size={16}/></div>
                             <div className="flex-1">
                                 <label className="text-xs text-gray-500 font-bold uppercase block mb-0.5">Địa chỉ thửa đất</label>
                                 <div className="text-sm text-gray-800 leading-snug">{formData.address || 'Chưa cập nhật'}</div>
                             </div>
                         </div>

                         <div className="grid grid-cols-2 gap-3 pt-2 border-t border-gray-100 mt-2">
                             <div className="flex items-center gap-3 p-2 rounded hover:bg-gray-50">
                                <div className="text-green-600 bg-green-100 p-1.5 rounded-md"><Ruler size={16}/></div>
                                <div>
                                    <label className="text-[10px] text-gray-400 font-bold uppercase block">Diện tích</label>
                                    <span className="text-sm font-mono font-bold text-gray-800">{formData.area ? Math.round(Number(formData.area)).toLocaleString() : '0'} m²</span>
                                </div>
                             </div>
                             <div className="flex items-center gap-3 p-2 rounded hover:bg-gray-50">
                                <div className="text-purple-600 bg-purple-100 p-1.5 rounded-md"><Tag size={16}/></div>
                                <div>
                                    <label className="text-[10px] text-gray-400 font-bold uppercase block">Loại đất</label>
                                    <span className="text-sm font-bold text-gray-800">{formData.landType}</span>
                                </div>
                             </div>
                         </div>
                     </div>

                    {/* Action Buttons */}
                    <div className="flex gap-2 pt-2 border-t border-gray-100">
                        {canEdit && (
                            <button className="flex-1 bg-white border border-gray-300 text-gray-700 py-2.5 rounded-lg text-xs font-bold hover:bg-gray-50 hover:text-blue-600 hover:border-blue-300 transition-all shadow-sm">
                                Chỉnh sửa
                            </button>
                        )}
                        <button 
                            onClick={handleExportPDF} 
                            disabled={isGeneratingPDF}
                            className="flex-1 bg-blue-600 text-white py-2.5 rounded-lg text-xs font-bold hover:bg-blue-700 shadow-md hover:shadow-lg flex items-center justify-center gap-2 transition-all active:scale-95"
                        >
                            {isGeneratingPDF ? <Loader2 size={16} className="animate-spin"/> : <Printer size={16} />}
                            Xuất Trích lục
                        </button>
                    </div>
                </div>
             </div>
         )}
      </div>

      {/* --- UI OVERLAYS (Buttons, Loading, etc) --- */}

      {isFetchingInfo && (
          <div className="absolute top-0 left-1/2 transform -translate-x-1/2 z-[800] bg-blue-600 text-white px-6 py-1.5 rounded-b-lg shadow-lg flex items-center gap-2 text-sm font-medium animate-in slide-in-from-top-4">
              <Loader2 size={14} className="animate-spin" />
              Đang truy vấn lớp WMS...
          </div>
      )}

      {fetchError && (
          <div className="absolute top-16 left-1/2 transform -translate-x-1/2 z-[1000] bg-red-900/90 backdrop-blur-sm text-white px-6 py-4 rounded-lg shadow-2xl border border-red-500 max-w-lg flex flex-col gap-2 animate-in slide-in-from-top-4">
              <div className="flex items-center gap-2 text-red-300 font-bold"><WifiOff size={20} /> Lỗi truy vấn dữ liệu</div>
              <p className="text-sm text-gray-200 whitespace-pre-line">{fetchError}</p>
              <button onClick={() => setFetchError(null)} className="mt-2 w-full bg-white text-red-900 font-bold py-2 rounded hover:bg-gray-200 flex items-center justify-center gap-2">
                  <X size={16} /> Đóng
              </button>
          </div>
      )}

      {/* --- COORDINATE DISPLAY (Bottom Left) --- */}
      <div className="absolute bottom-1 left-1 z-[400] bg-white/80 backdrop-blur-sm px-3 py-1 rounded border border-gray-300 text-xs font-mono text-gray-700 shadow-sm flex gap-4">
          <div className="flex items-center gap-1"><span className="font-bold text-gray-500">Lon:</span> {mouseCoords?.lon || '--'}</div>
          <div className="flex items-center gap-1"><span className="font-bold text-gray-500">Lat:</span> {mouseCoords?.lat || '--'}</div>
      </div>

      {/* --- MEASURE TOOLS (Top Center/Right) --- */}
      <div className="absolute top-4 right-20 z-[400] bg-white rounded-lg shadow-lg border border-gray-200 flex overflow-hidden">
          <button 
              onClick={() => handleMeasureChange('LineString')} 
              className={`p-2 hover:bg-gray-100 transition-colors ${measureMode === 'LineString' ? 'bg-blue-100 text-blue-600' : 'text-gray-600'}`}
              title="Đo khoảng cách"
          >
              <Ruler size={20} />
          </button>
          <div className="w-px bg-gray-200"></div>
          <button 
              onClick={() => handleMeasureChange('Polygon')} 
              className={`p-2 hover:bg-gray-100 transition-colors ${measureMode === 'Polygon' ? 'bg-blue-100 text-blue-600' : 'text-gray-600'}`}
              title="Đo diện tích"
          >
              <Square size={20} />
          </button>
          <div className="w-px bg-gray-200"></div>
          <button 
              onClick={clearMeasurement} 
              className="p-2 hover:bg-red-50 text-gray-600 hover:text-red-600 transition-colors"
              title="Xóa kết quả đo"
          >
              <Trash2 size={20} />
          </button>
      </div>

      {/* --- NEW SEARCH UI --- */}
      <div className="absolute top-4 left-16 z-[400] flex flex-col gap-2">
           <button onClick={() => setIsSearchOpen(!isSearchOpen)} className={`p-3 bg-white rounded-lg shadow-lg hover:bg-gray-50 text-gray-700 transition-all ${isSearchOpen ? 'bg-blue-600 text-white hover:bg-blue-500' : ''}`} title="Tìm kiếm">
               <Search size={24} />
           </button>
           {isSearchOpen && (
               <div className="bg-white/95 backdrop-blur-sm p-4 rounded-xl shadow-2xl border border-gray-200 w-80 animate-in slide-in-from-left-4 duration-200">
                   <form onSubmit={handleSearch} className="flex flex-col gap-3">
                       {/* Table Selector */}
                       <div className="relative">
                           <Filter size={14} className="absolute left-3 top-3 text-gray-500"/>
                           <select 
                                className="w-full bg-gray-50 border border-gray-300 rounded px-3 pl-8 py-2 text-sm outline-none focus:border-blue-500 appearance-none"
                                value={searchForm.table}
                                onChange={e => setSearchForm({...searchForm, table: e.target.value})}
                           >
                               <option value="ALL">-- Tất cả Phường/Xã --</option>
                               {spatialTables.map((t: any) => (
                                   <option key={t.table_name} value={t.table_name}>{t.display_name || t.table_name}</option>
                               ))}
                           </select>
                           <ChevronDown size={14} className="absolute right-3 top-3 text-gray-400 pointer-events-none"/>
                       </div>

                       {/* Helper Text */}
                       <div className="flex items-center gap-1 text-[10px] text-gray-500 italic px-1">
                           <HelpCircle size={10} />
                           <span>Số Tờ/Thửa tìm chính xác. Tên tìm gần đúng.</span>
                       </div>

                       {/* Row for So To & So Thua */}
                       <div className="flex gap-2">
                           <div className="flex-1 relative">
                                <input 
                                    className="w-full bg-gray-50 border border-gray-300 rounded px-3 py-2 text-sm outline-none focus:border-blue-500" 
                                    placeholder="Số tờ (VD: 15)" 
                                    value={searchForm.soTo} 
                                    onChange={(e) => setSearchForm({...searchForm, soTo: e.target.value})} 
                                />
                           </div>
                           <div className="flex-1 relative">
                                <input 
                                    className="w-full bg-gray-50 border border-gray-300 rounded px-3 py-2 text-sm outline-none focus:border-blue-500" 
                                    placeholder="Số thửa (VD: 102)" 
                                    value={searchForm.soThua} 
                                    onChange={(e) => setSearchForm({...searchForm, soThua: e.target.value})} 
                                />
                           </div>
                       </div>

                       {/* Owner Name */}
                       <input 
                            className="w-full bg-gray-50 border border-gray-300 rounded px-3 py-2 text-sm outline-none focus:border-blue-500" 
                            placeholder="Tên chủ / Địa chỉ (tùy chọn)" 
                            value={searchForm.owner} 
                            onChange={(e) => setSearchForm({...searchForm, owner: e.target.value})} 
                       />

                       <button type="submit" className="bg-blue-600 text-white p-2 rounded hover:bg-blue-500 flex justify-center items-center gap-2 font-bold text-sm">
                           {isSearching ? <Loader2 size={16} className="animate-spin"/> : <Search size={16} />}
                           Tìm kiếm
                       </button>
                   </form>

                   {/* Results List */}
                   <div className="mt-4 max-h-60 overflow-y-auto custom-scrollbar space-y-2">
                       {searchResults.map(parcel => (
                           <div key={parcel.id} onClick={() => handleSelectSearchResult(parcel)} className="p-3 rounded bg-gray-50 hover:bg-blue-50 border border-gray-100 cursor-pointer transition-colors group">
                               <div className="font-bold text-gray-800 text-sm">Tờ: {parcel.properties['so_to']||'?'} - Thửa: {parcel.properties['so_thua']||'?'}</div>
                               <div className="text-xs text-gray-500 mt-1 truncate">Chủ: {parcel.properties.ownerName}</div>
                               {parcel.properties['tableDisplayName'] ? (
                                   <div className="text-[10px] text-blue-600 font-medium mt-1 border-t border-gray-200 pt-1 flex items-center gap-1">
                                       <Database size={10}/> {parcel.properties['tableDisplayName']}
                                   </div>
                               ) : parcel.properties['tableName'] && (
                                   <div className="text-[10px] text-blue-500 mt-1 italic border-t border-gray-200 pt-1">
                                       KV: {parcel.properties['tableName']}
                                   </div>
                               )}
