                      ))}
                  </div>
                  <div className="border-t border-gray-100 my-3"></div>
                  <h4 className="text-xs font-bold text-gray-500 uppercase mb-3 tracking-wider flex justify-between items-center">
                      <span>Lớp Dữ liệu (WMS)</span>
                      <span className="text-[10px] text-blue-500 font-normal bg-blue-100 px-2 py-0.5 rounded">Chọn lớp để truy vấn</span>
                  </h4>
                  <div className="space-y-2">
                      {availableLayers.length === 0 ? <div className="text-xs text-gray-400 italic">Trống...</div> : availableLayers.map(l => {
                            const isActive = activeLayerId === l.id;
                            const isVisible = visibleLayerIds.includes(l.id);

                            return (
                                <div key={l.id} className={`flex items-center justify-between p-2 rounded transition-all cursor-pointer border ${isActive ? 'bg-blue-50 border-blue-200 ring-1 ring-blue-300' : 'hover:bg-gray-50 border-transparent'}`}>
                                    {/* CLICK NAME -> SET ACTIVE LAYER */}
                                    <div className="flex items-center gap-3 flex-1" onClick={() => handleSelectActiveLayer(l.id)}>
                                        <div className={`transition-colors ${isActive ? "text-blue-600" : "text-gray-400"}`}>
                                            {isActive ? <MousePointerClick size={18} className="animate-pulse" /> : <MapPin size={18} />}
                                        </div>
                                        <span className={`text-sm font-medium ${isActive ? 'text-blue-700' : 'text-gray-700'}`}>{l.name}</span>
                                    </div>
                                    {/* CLICK EYE -> TOGGLE VISIBILITY */}
                                    <button onClick={(e) => { e.stopPropagation(); toggleLayer(l.id); }} className={`text-gray-400 p-1 hover:bg-gray-200 rounded ${isVisible ? 'text-blue-600' : ''}`}>
                                        {isVisible ? <Eye size={18} /> : <EyeOff size={18} />}
                                    </button>
                                </div>
                            );
                      })}
                  </div>
              </div>
          )}
      </div>

      <div className="absolute bottom-24 right-4 z-[400]">
          <button onClick={handleLocateMe} className="p-3 bg-white rounded-lg shadow-lg hover:bg-gray-50 text-gray-700" title="Vị trí của tôi">
              {isLocating ? <Loader2 size={24} className="animate-spin text-blue-600"/> : <Crosshair size={24} />}
          </button>
      </div>

       {/* --- HIDDEN PRINT TEMPLATE --- */}
       <div className="absolute top-0 left-0 z-[-50]">
          <div ref={printTemplateRef} id="print-template" className="w-[210mm] bg-white py-[10mm] px-[15mm] flex flex-col items-center" style={{ fontFamily: '"Times New Roman", Times, serif', color: '#000000', backgroundColor: '#ffffff' }}>

              <div className="text-center mb-4">
                  <h3 className="font-bold text-lg uppercase" style={{color:'#000'}}>CỘNG HÒA XÃ HỘI CHỦ NGHĨA VIỆT NAM</h3>
                  <p className="font-bold text-sm underline underline-offset-4" style={{color:'#000'}}>Độc lập - Tự do - Hạnh phúc</p>
              </div>

              <h1 className="text-2xl font-bold uppercase mb-4 text-center" style={{color:'#000'}}>TRÍCH LỤC BẢN ĐỒ ĐỊA CHÍNH</h1>

              <div className="w-full mb-4 text-sm leading-6" style={{color:'#000'}}>
                   <p><strong>1. Thửa đất số:</strong> {getAttribute(formData, ['sothututhu', 'so_thua', 'sothua', 'shthua', 'st', 'sh_thua', 'thua', 'thua_dat', 'so_thu_tu_thua']) || '...'} 
                      <span className="ml-12"><strong>Tờ bản đồ số:</strong> {getAttribute(formData, ['sohieutoba', 'so_to', 'sodoto', 'shmap', 't', 'sh_to', 'shb', 'to_ban_do', 'tobando', 'so_hieu_to_ban_do']) || '...'}</span>
                   </p>
                   <p><strong>2. Địa chỉ thửa đất:</strong> {getAttribute(formData, ['dia_chi', 'diachi', 'address', 'dc', 'khu_vuc', 'vi_tri', 'dia_chi_thua_dat']) || '...'}</p>
                   <p><strong>3. Diện tích:</strong> {getAttribute(formData, ['dientich', 'dien_tich', 'shape_area', 'area', 'dt', 'poly_area', 'st_area(shape)', 'st_area(geometry)', 'dien_tich_phap_ly']) || '...'} m²</p>
                   <p><strong>4. Mục đích sử dụng:</strong> {getAttribute(formData, ['landType', 'loai_dat', 'kh', 'muc_dich', 'mdsd', 'ma_loai_dat']) === 'Residential' ? 'Đất ở' : (getAttribute(formData, ['landType', 'loai_dat', 'kh', 'muc_dich', 'mdsd']) || 'Đất nông nghiệp')}</p>
                   <p><strong>5. Tên người sử dụng đất:</strong> <span className="uppercase font-bold">{getAttribute(formData, ['ten_chu', 'tenchu', 'chu_so_huu', 'owner', 'name', 'ownerName', 'chusudung', 'ho_ten', 'chusd', 'ten', 'chu', 'name_vn', 'full_name', 'chu_su_dung']) || '...'}</span></p>
              </div>

              <div className="w-full flex flex-col items-center border border-black p-1 mb-2" style={{borderColor: '#000'}}>
                   <p className="w-full text-left font-bold mb-1 text-sm italic" style={{color:'#000'}}>6. Sơ đồ thửa đất:</p>
                   <canvas ref={parcelCanvasRef} width={600} height={350} className="w-full" />
              </div>

              <div className="w-full mb-4">
                   <p className="font-bold text-sm mb-1 italic" style={{color:'#000'}}>7. Bảng kê tọa độ và khoảng cách:</p>
                   <table className="w-full border-collapse text-sm text-center border border-black" style={{borderColor: '#000', color: '#000'}}>
                       <thead>
                           <tr style={{backgroundColor: '#e5e7eb'}}>
                               <th className="border border-black py-1 w-16 font-bold" style={{color: '#000', borderColor: '#000'}}>Hiệu đỉnh</th>
                               <th className="border border-black py-1 font-bold" style={{color: '#000', borderColor: '#000'}}>Tọa độ X (m)</th>
                               <th className="border border-black py-1 font-bold" style={{color: '#000', borderColor: '#000'}}>Tọa độ Y (m)</th>
                               <th className="border border-black py-1 font-bold" style={{color: '#000', borderColor: '#000'}}>Cạnh (m)</th>
                           </tr>
                       </thead>
                       <tbody>
                           {geometryPoints.map((p, i) => (
                               <tr key={i}>
                                   <td className="border border-black py-1 font-bold" style={{color: '#000', borderColor: '#000'}}>{p.id}</td>
                                   <td className="border border-black py-1" style={{color: '#000', borderColor: '#000'}}>{p.x.toFixed(2)}</td>
                                   <td className="border border-black py-1" style={{color: '#000', borderColor: '#000'}}>{p.y.toFixed(2)}</td>
                                   <td className="border border-black py-1 font-semibold" style={{color: '#000', borderColor: '#000'}}>{p.distanceNext ? p.distanceNext : '-'}</td>
                               </tr>
                           ))}
                       </tbody>
                   </table>
              </div>

              <div className="w-full flex justify-end mt-2" style={{color:'#000'}}>
                  <div className="text-center w-1/2">
                      <p className="italic">Tp. Hồ Chí Minh, ngày {new Date().getDate()} tháng {new Date().getMonth() + 1} năm {new Date().getFullYear()}</p>
                      <p className="font-bold uppercase mt-1">Người trích lục</p>
                      <div className="h-24"></div> 
                      <p className="italic text-xs mb-1">(Ký, ghi rõ họ tên)</p>
                      <p className="font-bold uppercase">{(user && user.name && user.name.trim() !== '') ? user.name : 'Thượng Hồng Thái'}</p>
                  </div>
              </div>
          </div>
      </div>

    </div>
  );
};

export default MapPage;

import React, { useEffect, useRef, useState } from 'react';
import { User, LandParcel, UserRole, WMSLayerConfig } from '../types';
import { gisService, API_URL } from '../services/mockBackend';
import { Layers, MousePointer2, Save, Trash2, X, AlertTriangle, CheckCircle, MapPin, Globe, Map as MapIcon, Eye, EyeOff, Info, List, FileText, WifiOff, RefreshCw, Search, Loader2, Printer, Navigation, Crosshair, ChevronDown, Table as TableIcon, User as UserIcon, Ruler, Tag, MousePointerClick, Filter, HelpCircle, Square, Database } from 'lucide-react';
import { jsPDF } from "jspdf";
import html2canvas from "html2canvas";
import proj4 from "proj4";

// OpenLayers uses global 'ol' from CDN
declare const ol: any;

// --- CẤU HÌNH HỆ TỌA ĐỘ VN-2000 ---
proj4.defs("EPSG:9210", "+proj=tmerc +lat_0=0 +lon_0=105.75 +k=0.9999 +x_0=500000 +y_0=0 +ellps=WGS84 +towgs84=-191.90441429,-39.30318279,-111.45032835,0.00928836,0.01975479,-0.00427372,0.252906278 +units=m +no_defs");

interface MapPageProps {
  user: User | null;
}

const MapPage: React.FC<MapPageProps> = ({ user }) => {
  const mapElement = useRef<HTMLDivElement>(null);
  const mapInstance = useRef<any>(null);
  const popupElement = useRef<HTMLDivElement>(null);
  const popupOverlay = useRef<any>(null);

  // Layer Refs
  const osmLayer = useRef<any>(null);
  const googleLayer = useRef<any>(null);
  const vietbandoLayer = useRef<any>(null);
  const wmsLayerGroup = useRef<any>(null);
  const vectorLayer = useRef<any>(null); // For local parcels
  const highlightLayer = useRef<any>(null); // For selection highlight

  // Measure Refs
  const drawSource = useRef<any>(new ol.source.Vector());
  const drawLayer = useRef<any>(null);
  const drawInteraction = useRef<any>(null);
  const measureTooltips = useRef<any[]>([]); // Store active tooltips to clear later

  // State
  const [selectedParcel, setSelectedParcel] = useState<LandParcel | null>(null);
  const [isEditing, setIsEditing] = useState(false);
  const [formData, setFormData] = useState<any>({});

  // Search State
  const [spatialTables, setSpatialTables] = useState<any[]>([]); // Danh sách xã/phường objects
  const [searchForm, setSearchForm] = useState({
      table: 'ALL',
      soTo: '',
      soThua: '',
      owner: ''
  });
  const [searchResults, setSearchResults] = useState<LandParcel[]>([]);
  const [isSearching, setIsSearching] = useState(false);
  const [isSearchOpen, setIsSearchOpen] = useState(false);

  // Layer Control State
  const [activeBaseLayer, setActiveBaseLayer] = useState<'OSM' | 'GOOGLE' | 'VIETBANDO'>('OSM');
  const [availableLayers, setAvailableLayers] = useState<WMSLayerConfig[]>([]);
  const [visibleLayerIds, setVisibleLayerIds] = useState<string[]>([]);
  const [activeLayerId, setActiveLayerId] = useState<string | null>(null); // NEW: Layer được chọn để truy vấn
  const [isLayerMenuOpen, setIsLayerMenuOpen] = useState(false);

  const [isGeneratingPDF, setIsGeneratingPDF] = useState(false);
  const [isLocating, setIsLocating] = useState(false);
  const [isFetchingInfo, setIsFetchingInfo] = useState(false);
  const [fetchError, setFetchError] = useState<string | null>(null);

  // Coordinate & Measure State
  const [mouseCoords, setMouseCoords] = useState<{lon: string, lat: string} | null>(null);
  const [measureMode, setMeasureMode] = useState<'LineString' | 'Polygon' | null>(null);

  // Print Template Refs
  const printTemplateRef = useRef<HTMLDivElement>(null);
  const parcelCanvasRef = useRef<HTMLCanvasElement>(null);
  const [geometryPoints, setGeometryPoints] = useState<any[]>([]);

  // 1. Initial Load of Layers Config & Spatial Tables
  useEffect(() => {
      const initData = async () => {
          try {
              // Load WMS Layers
              const layers = await gisService.getLayers();
              setAvailableLayers(layers);
              const defaults = layers.filter(l => l.visible).map(l => l.id);
              setVisibleLayerIds(defaults);
              if (layers.length > 0) setActiveLayerId(layers[0].id);

              // Load Spatial Tables (Phường/Xã) for Search
              const tables = await gisService.getSpatialTables();
              setSpatialTables(tables);
          } catch (e) { console.error("Failed to load initial data", e); }
      };
      initData();
  }, []);

  // 2. Initialize OpenLayers Map
  useEffect(() => {
      if (!mapElement.current || mapInstance.current) return;
      if (typeof ol === 'undefined') {
          console.error("OpenLayers not loaded!"); 
          return;
      }

      // --- Base Layers ---
