      {/* --- POPUP CONTAINER (OPENLAYERS OVERLAY) --- */}
      <div ref={popupElement} className="ol-popup min-w-[320px]">
         {selectedParcel && (
             <div className="flex flex-col w-full bg-white rounded-xl overflow-hidden shadow-2xl border border-gray-300 font-sans">
                {/* Header with Source Badge */}
                <div className="bg-gradient-to-r from-blue-700 to-blue-600 text-white p-3 flex justify-between items-start shadow-sm">
                    <div>
                        <h3 className="font-bold flex items-center gap-2 text-base">
                            <Info size={18} className="text-blue-200" /> Thông tin Chi tiết
                        </h3>
                        {/* Source Label */}
                        <div className="flex items-center gap-1 text-[11px] text-blue-100 mt-1 bg-blue-800/40 w-fit px-2 py-0.5 rounded-full border border-blue-400/30">
                            <Database size={10} />
                            <span>Nguồn: </span>
                            <span className="font-bold text-white">
                                {formData.tableDisplayName || formData.tableName || 'WMS Service'}
                            </span>
                        </div>
                    </div>
                    <button onClick={() => {
                        setIsEditing(false);
                        setSelectedParcel(null);
                        popupElement.current!.style.display = 'none';
                        if(highlightLayer.current) highlightLayer.current.getSource().clear();
                        popupOverlay.current.setPosition(undefined); 
                    }} className="hover:bg-white/20 rounded p-1 transition-colors"><X size={18} /></button>
                </div>

                <div className="p-4 space-y-4">
                     {/* Info Cards */}
                     <div className="flex gap-3">
                         <div className="flex-1 bg-gray-50 border border-gray-200 rounded-lg p-2.5 text-center shadow-sm">
                             <div className="text-[10px] text-gray-500 font-bold uppercase tracking-wider mb-1">Tờ bản đồ</div>
                             <div className="text-2xl font-extrabold text-blue-600">{formData.so_to || '?'}</div>
                         </div>
                         <div className="flex-1 bg-gray-50 border border-gray-200 rounded-lg p-2.5 text-center shadow-sm">
                             <div className="text-[10px] text-gray-500 font-bold uppercase tracking-wider mb-1">Số thửa</div>
                             <div className="text-2xl font-extrabold text-blue-600">{formData.so_thua || '?'}</div>
                         </div>
                     </div>

                     <div className="space-y-3">
                         <div className="flex items-start gap-3 p-2 hover:bg-gray-50 rounded transition-colors">
                             <div className="bg-blue-100 p-2 rounded-full text-blue-600 mt-0.5"><UserIcon size={16}/></div>
                             <div className="flex-1">
                                 <label className="text-xs text-gray-500 font-bold uppercase block mb-0.5">Chủ sở hữu</label>
                                 <div className="text-sm font-bold text-gray-900">{formData.ownerName || 'Chưa xác định'}</div>
                             </div>
                         </div>

                         <div className="flex items-start gap-3 p-2 hover:bg-gray-50 rounded transition-colors">
                             <div className="bg-orange-100 p-2 rounded-full text-orange-600 mt-0.5"><MapPin size={16}/></div>
                             <div className="flex-1">
                                 <label className="text-xs text-gray-500 font-bold uppercase block mb-0.5">Địa chỉ thửa đất</label>
                                 <div className="text-sm text-gray-800 leading-snug">{formData.address || 'Chưa cập nhật'}</div>
                             </div>
                         </div>

                         <div className="grid grid-cols-2 gap-3 pt-2 border-t border-gray-100 mt-2">
                             <div className="flex items-center gap-3 p-2 rounded hover:bg-gray-50">
                                <div className="text-green-600 bg-green-100 p-1.5 rounded-md"><Ruler size={16}/></div>
                                <div>
                                    <label className="text-[10px] text-gray-400 font-bold uppercase block">Diện tích</label>
                                    <span className="text-sm font-mono font-bold text-gray-800">{formData.area ? Math.round(Number(formData.area)).toLocaleString() : '0'} m²</span>
                                </div>
                             </div>
                             <div className="flex items-center gap-3 p-2 rounded hover:bg-gray-50">
                                <div className="text-purple-600 bg-purple-100 p-1.5 rounded-md"><Tag size={16}/></div>
                                <div>
                                    <label className="text-[10px] text-gray-400 font-bold uppercase block">Loại đất</label>
                                    <span className="text-sm font-bold text-gray-800">{formData.landType}</span>
                                </div>
                             </div>
                         </div>
                     </div>

                    {/* Action Buttons */}
                    <div className="flex gap-2 pt-2 border-t border-gray-100">
                        {canEdit && (
                            <button className="flex-1 bg-white border border-gray-300 text-gray-700 py-2.5 rounded-lg text-xs font-bold hover:bg-gray-50 hover:text-blue-600 hover:border-blue-300 transition-all shadow-sm">
                                Chỉnh sửa
                            </button>
                        )}
                        <button 
                            onClick={handleExportPDF} 
                            disabled={isGeneratingPDF}
                            className="flex-1 bg-blue-600 text-white py-2.5 rounded-lg text-xs font-bold hover:bg-blue-700 shadow-md hover:shadow-lg flex items-center justify-center gap-2 transition-all active:scale-95"
                        >
                            {isGeneratingPDF ? <Loader2 size={16} className="animate-spin"/> : <Printer size={16} />}
                            Xuất Trích lục
                        </button>
                    </div>
                </div>
             </div>
         )}
      </div>

      {/* --- UI OVERLAYS (Buttons, Loading, etc) --- */}

      {isFetchingInfo && (
          <div className="absolute top-0 left-1/2 transform -translate-x-1/2 z-[800] bg-blue-600 text-white px-6 py-1.5 rounded-b-lg shadow-lg flex items-center gap-2 text-sm font-medium animate-in slide-in-from-top-4">
              <Loader2 size={14} className="animate-spin" />
              Đang truy vấn lớp WMS...
          </div>
      )}

      {fetchError && (
          <div className="absolute top-16 left-1/2 transform -translate-x-1/2 z-[1000] bg-red-900/90 backdrop-blur-sm text-white px-6 py-4 rounded-lg shadow-2xl border border-red-500 max-w-lg flex flex-col gap-2 animate-in slide-in-from-top-4">
              <div className="flex items-center gap-2 text-red-300 font-bold"><WifiOff size={20} /> Lỗi truy vấn dữ liệu</div>
              <p className="text-sm text-gray-200 whitespace-pre-line">{fetchError}</p>
              <button onClick={() => setFetchError(null)} className="mt-2 w-full bg-white text-red-900 font-bold py-2 rounded hover:bg-gray-200 flex items-center justify-center gap-2">
