// XÁC ĐỊNH URL API CHÍNH XÁC
const hostname = window.location.hostname;
const isLocal = hostname === 'localhost' || hostname === '127.0.0.1' || hostname.startsWith('192.168.');

// Nếu Local -> Port 3004. Nếu Server (geo.gisvn.space) -> API HTTPS chuẩn (không port)
export const API_URL = isLocal 
    ? `http://${hostname}:3004` 
    : 'https://apigeo.gisvn.space';

// Helper để xử lý Circular JSON
const safeStringify = (obj: any) => {
    const seen = new WeakSet();
    try {
        return JSON.stringify(obj, (key, value) => {
            if (typeof value === "object" && value !== null) {
                if (seen.has(value)) return;
                seen.add(value);
            }
            return value;
        });
    } catch (e) { return "{}"; }
};

// Generic API Call Helper
const apiCall = async (endpoint: string, options?: RequestInit) => {
    try {
        // Get user from local storage to pass context for logging
        const userStr = localStorage.getItem('geo_user');
        const headers: any = { 'Content-Type': 'application/json', ...options?.headers };

        if (userStr) {
            try {
                const u = JSON.parse(userStr);
                headers['x-user-id'] = u.id;
                headers['x-user-name'] = encodeURIComponent(u.name); // Encode for safe header
                headers['x-branch-id'] = u.branchId;
            } catch (e) {}
        }

        const res = await fetch(`${API_URL}${endpoint}`, {
             ...options,
             headers: headers
        });

        if (!res.ok) {
            const errorText = await res.text();
            // Suppress log for expected 404s or known init errors
            if (res.status !== 404 && !endpoint.includes('spatial-tables')) {
                console.error(`[API Error] ${endpoint} returned ${res.status}:`, errorText);
            }
            throw new Error(`API Error ${res.status}: ${errorText || res.statusText}`);
        }
        return await res.json();
    } catch (error: any) {
        throw new Error(`Fetch không tải được: ${error.message}`);
    }
};

// --- NEW: Helper to get Auth Headers for non-JSON requests ---
const getAuthHeaders = () => {
    const headers: any = {};
    const userStr = localStorage.getItem('geo_user');
    if (userStr) {
        try {
            const u = JSON.parse(userStr);
            headers['x-user-id'] = u.id;
            headers['x-user-name'] = encodeURIComponent(u.name);
            headers['x-branch-id'] = u.branchId;
        } catch (e) {}
    }
    return headers;
};

