    updateWmsLayer: async (layer: any) => await apiCall(`/api/wms-layers/${layer.id}`, { method: 'PUT', body: JSON.stringify(layer) }),
    deleteWmsLayer: async (id: string) => await apiCall(`/api/wms-layers/${id}`, { method: 'DELETE' }),

    // Role Permissions
    getRolePermissions: async () => await apiCall('/api/role-permissions'),
    saveRolePermissions: async (role: UserRole, permissions: string[]) => 
        await apiCall('/api/role-permissions', { method: 'POST', body: JSON.stringify({ role, permissions }) }),

    // --- DATABASE BACKUP & RESTORE ---
    createBackup: async () => {
        // Trigger download
        const res = await fetch(`${API_URL}/api/system/backup`, { headers: getAuthHeaders() });
        if (!res.ok) throw new Error('Backup failed');
        const blob = await res.blob();
        const url = window.URL.createObjectURL(blob);
        const a = document.createElement('a');
        a.href = url;
        const contentDisposition = res.headers.get('Content-Disposition');
        let fileName = `backup-${new Date().toISOString().slice(0,10)}.sql`;
        if (contentDisposition && contentDisposition.indexOf('attachment') !== -1) {
             const filenameRegex = /filename[^;=\n]*=((['"]).*?\2|[^;\n]*)/;
             const matches = filenameRegex.exec(contentDisposition);
             if (matches != null && matches[1]) { 
               fileName = matches[1].replace(/['"]/g, '');
             }
        }
        a.download = fileName;
        document.body.appendChild(a);
        a.click();
        a.remove();
        window.URL.revokeObjectURL(url);
    },

    restoreDatabase: async (file: File) => {
        const formData = new FormData();
        formData.append('file', file);
        const res = await fetch(`${API_URL}/api/system/restore`, {
            method: 'POST',
            headers: getAuthHeaders(),
            body: formData
        });
        if (!res.ok) {
            const errorText = await res.text();
            throw new Error(`Restore failed: ${errorText}`);
        }
        return await res.json();
    }
};

