        if (overrideUser) {
            userId = overrideUser.id;
            userName = overrideUser.name;
            branchId = overrideUser.branch_id || overrideUser.branchId;
        } else {
            userId = req.headers['x-user-id'] || 'unknown';
            userName = req.headers['x-user-name'] ? decodeURIComponent(req.headers['x-user-name']) : 'System';
            branchId = req.headers['x-branch-id'] || 'HEAD_OFFICE';
        }

        if (userId === 'unknown' && action !== 'SYSTEM_AUTO') return;

        await pool.query(
            `INSERT INTO system_logs (user_id, user_name, action, details, branch_id) VALUES ($1, $2, $3, $4, $5)`,
            [userId, userName, action, details, branchId]
        );
