      {/* --- COORDINATE DISPLAY (Bottom Left) --- */}
      <div className="absolute bottom-1 left-1 z-[400] bg-white/80 backdrop-blur-sm px-3 py-1 rounded border border-gray-300 text-xs font-mono text-gray-700 shadow-sm flex gap-4">
          <div className="flex items-center gap-1"><span className="font-bold text-gray-500">Lon:</span> {mouseCoords?.lon || '--'}</div>
          <div className="flex items-center gap-1"><span className="font-bold text-gray-500">Lat:</span> {mouseCoords?.lat || '--'}</div>
      </div>

      {/* --- MEASURE TOOLS (Top Center/Right) --- */}
      <div className="absolute top-4 right-20 z-[400] bg-white rounded-lg shadow-lg border border-gray-200 flex overflow-hidden">
          <button 
              onClick={() => handleMeasureChange('LineString')} 
              className={`p-2 hover:bg-gray-100 transition-colors ${measureMode === 'LineString' ? 'bg-blue-100 text-blue-600' : 'text-gray-600'}`}
              title="Đo khoảng cách"
