                    </div>
                </div>
             </div>
         )}
      </div>

      {/* --- UI OVERLAYS (Buttons, Loading, etc) --- */}

      {isFetchingInfo && (
          <div className="absolute top-0 left-1/2 transform -translate-x-1/2 z-[800] bg-blue-600 text-white px-6 py-1.5 rounded-b-lg shadow-lg flex items-center gap-2 text-sm font-medium animate-in slide-in-from-top-4">
              <Loader2 size={14} className="animate-spin" />
