      {/* --- POPUP CONTAINER (OPENLAYERS OVERLAY) --- */}
      <div ref={popupElement} className="ol-popup min-w-[320px]">
         {selectedParcel && (
             <div className="flex flex-col w-full bg-white rounded-xl overflow-hidden shadow-2xl border border-gray-300 font-sans">
                {/* Header with Source Badge */}
                <div className="bg-gradient-to-r from-blue-700 to-blue-600 text-white p-3 flex justify-between items-start shadow-sm">
                    <div>
                        <h3 className="font-bold flex items-center gap-2 text-base">
                            <Info size={18} className="text-blue-200" /> Thông tin Chi tiết
                        </h3>
                        {/* Source Label */}
                        <div className="flex items-center gap-1 text-[11px] text-blue-100 mt-1 bg-blue-800/40 w-fit px-2 py-0.5 rounded-full border border-blue-400/30">
                            <Database size={10} />
                            <span>Nguồn: </span>
                            <span className="font-bold text-white">
                                {formData.tableDisplayName || formData.tableName || 'WMS Service'}
                            </span>
                        </div>
                    </div>
                    <button onClick={() => {
                        setIsEditing(false);
                        setSelectedParcel(null);
                        popupElement.current!.style.display = 'none';
                        if(highlightLayer.current) highlightLayer.current.getSource().clear();
                        popupOverlay.current.setPosition(undefined); 
                    }} className="hover:bg-white/20 rounded p-1 transition-colors"><X size={18} /></button>
                </div>

                <div className="p-4 space-y-4">
                     {/* Info Cards */}
                     <div className="flex gap-3">
                         <div className="flex-1 bg-gray-50 border border-gray-200 rounded-lg p-2.5 text-center shadow-sm">
                             <div className="text-[10px] text-gray-500 font-bold uppercase tracking-wider mb-1">Tờ bản đồ</div>
                             <div className="text-2xl font-extrabold text-blue-600">{formData.so_to || '?'}</div>
                         </div>
                         <div className="flex-1 bg-gray-50 border border-gray-200 rounded-lg p-2.5 text-center shadow-sm">
                             <div className="text-[10px] text-gray-500 font-bold uppercase tracking-wider mb-1">Số thửa</div>
                             <div className="text-2xl font-extrabold text-blue-600">{formData.so_thua || '?'}</div>
                         </div>
                     </div>

                     <div className="space-y-3">
                         <div className="flex items-start gap-3 p-2 hover:bg-gray-50 rounded transition-colors">
                             <div className="bg-blue-100 p-2 rounded-full text-blue-600 mt-0.5"><UserIcon size={16}/></div>
                             <div className="flex-1">
                                 <label className="text-xs text-gray-500 font-bold uppercase block mb-0.5">Chủ sở hữu</label>
