import express from 'express';
import cors from 'cors';
import pg from 'pg';
import multer from 'multer'; // Upload file handler
import shp from 'shpjs';     // Read Shapefile .zip
import dbConfig from './db_config.js';
import os from 'os';         // System info
import { spawn } from 'child_process'; // Execute shell commands for DB Backup/Restore

const { Pool } = pg;

const app = express();
const port = 3004;

// --- FIX: Trust Proxy (Required behind Nginx/Cloudflare) ---
app.enable('trust proxy');

// --- FIX CORS: Robust Configuration ---
const allowedOrigins = [
    'https://geo.gisvn.space', 
    'https://www.geo.gisvn.space', 
    'https://apigeo.gisvn.space', 
    'http://localhost:3003',
    'http://localhost:5173',
    'http://127.0.0.1:3003',
    'http://127.0.0.1:5173'
];

const corsOptions = {
    origin: function (origin, callback) {
        // Allow requests with no origin (like mobile apps or curl requests)
        if (!origin) return callback(null, true);

        if (allowedOrigins.indexOf(origin) !== -1) {
            callback(null, true);
        } else {
            // Allow mostly everything for development stability
            callback(null, true);
        }
    },
    credentials: true, // Allow cookies/auth headers
    methods: ['GET', 'POST', 'PUT', 'DELETE', 'OPTIONS', 'PATCH'],
    allowedHeaders: ['Content-Type', 'Authorization', 'x-user-id', 'x-user-name', 'x-branch-id', 'X-Requested-With', 'Accept', 'Origin'],
    exposedHeaders: ['Content-Range', 'X-Content-Range', 'Content-Disposition'],
    optionsSuccessStatus: 200
};

app.use(cors(corsOptions));
// Tăng giới hạn payload để hỗ trợ upload ảnh base64 qua JSON
app.use(express.json({ limit: '50mb' }));
app.use(express.urlencoded({ limit: '50mb', extended: true }));

// Multer memory storage
const upload = multer({ storage: multer.memoryStorage() });

const pool = new Pool(dbConfig);

// ----------------------------------------------------
// LOGGING HELPER
// ----------------------------------------------------
const logSystemAction = async (req, action, details, overrideUser = null) => {
    try {
        let userId, userName, branchId;

        if (overrideUser) {
            userId = overrideUser.id;
            userName = overrideUser.name;
            branchId = overrideUser.branch_id || overrideUser.branchId;
        } else {
            userId = req.headers['x-user-id'] || 'unknown';
            userName = req.headers['x-user-name'] ? decodeURIComponent(req.headers['x-user-name']) : 'System';
            branchId = req.headers['x-branch-id'] || 'HEAD_OFFICE';
        }

        if (userId === 'unknown' && action !== 'SYSTEM_AUTO') return;

        await pool.query(
            `INSERT INTO system_logs (user_id, user_name, action, details, branch_id) VALUES ($1, $2, $3, $4, $5)`,
            [userId, userName, action, details, branchId]
        );
    } catch (e) {
        console.error("⚠️ Failed to write system log:", e.message);
    }
};

