// 3. Link Existing Table (Normalize)
app.post('/api/spatial-tables/link', async (req, res) => {
    try {
        const { tableName, displayName } = req.body;
        const safeName = tableName.toLowerCase().replace(/[^a-z0-9_]/g, '');

        const check = await pool.query(`SELECT to_regclass($1) as exists`, [safeName]);
        if (!check.rows[0].exists) return res.status(404).json({error: `Bảng '${safeName}' không tồn tại trong Database.`});

        await pool.query(`INSERT INTO spatial_tables_registry (table_name, display_name) VALUES ($1, $2) ON CONFLICT (table_name) DO NOTHING`, [safeName, displayName || safeName]);

        const colsRes = await pool.query(`SELECT column_name FROM information_schema.columns WHERE table_name = $1`, [safeName]);
        const cols = colsRes.rows.map(r => r.column_name.toLowerCase());

        const client = await pool.connect();
        try {
            await client.query('BEGIN');
            const standardCols = [
                { name: 'sothua', type: 'VARCHAR(50)' },
                { name: 'sodoto', type: 'VARCHAR(50)' },
                { name: 'tenchu', type: 'VARCHAR(255)' },
                { name: 'diachi', type: 'TEXT' },
                { name: 'dientich', type: 'NUMERIC' },
                { name: 'geometry', type: 'GEOMETRY(Polygon, 4326)' },
                { name: 'properties', type: 'JSONB' }
            ];
            const renameMap = {
                'shthua': 'sothua', 'parcel_no': 'sothua', 'so_thua': 'sothua',
                'shmap': 'sodoto', 'map_sheet': 'sodoto', 'so_to': 'sodoto',
                'owner': 'tenchu', 'chu_so_huu': 'tenchu', 'ten_chu': 'tenchu',
                'address': 'diachi', 'dia_chi': 'diachi',
                'area': 'dientich', 'shape_area': 'dientich', 'dien_tich': 'dientich',
                'geom': 'geometry', 'shape': 'geometry'
            };

            for (const col of cols) {
                if (renameMap[col] && !cols.includes(renameMap[col])) {
                     await client.query(`ALTER TABLE "${safeName}" RENAME COLUMN "${col}" TO "${renameMap[col]}"`);
                     cols.push(renameMap[col]);
                }
            }
            for (const std of standardCols) {
                if (!cols.includes(std.name)) {
                     await client.query(`ALTER TABLE "${safeName}" ADD COLUMN "${std.name}" ${std.type}`);
                }
            }
            if (!cols.includes('gid')) {
                await client.query(`ALTER TABLE "${safeName}" ADD COLUMN gid SERIAL PRIMARY KEY`);
            }
            await client.query('COMMIT');
        } catch(e) {
            await client.query('ROLLBACK');
            throw e;
        } finally {
            client.release();
        }
        await logSystemAction(req, 'LINK_TABLE', `Liên kết và chuẩn hóa bảng: ${safeName}`);
        res.json({status:'ok', tableName: safeName});
    } catch(e) { res.status(500).json({error:e.message}); }
});

