          {isLayerMenuOpen && (
              <div className="bg-white/95 backdrop-blur-sm p-4 rounded-xl shadow-2xl border border-gray-200 w-72 animate-in slide-in-from-right-10 duration-200">
                  <h4 className="text-xs font-bold text-gray-500 uppercase mb-3 tracking-wider">Nền Bản đồ</h4>
                  <div className="space-y-2 mb-4">
