                                    className="px-6 py-3 bg-gray-700 hover:bg-gray-600 text-white rounded-lg font-medium transition-colors"
                                >
                                    Hủy bỏ
                                </button>
                                <button 
                                    onClick={executeDelete}
                                    className={`px-6 py-3 text-white rounded-lg font-bold shadow-lg transition-transform active:scale-95 ${
                                        deleteModal.type === 'UNLINK_TABLE' 
                                        ? 'bg-orange-600 hover:bg-orange-700 shadow-orange-900/50' 
                                        : 'bg-red-600 hover:bg-red-700 shadow-red-900/50'
                                    }`}
                                >
                                    {deleteModal.type === 'UNLINK_TABLE' ? 'Xác nhận Hủy' : 'Xác nhận Xóa'}
                                </button>
                            </div>
                        </div>
                    </div>
                </div>
            )}
        </div>
    );
};

