const mapRowToParcel = (row) => {
    const getVal = (obj, keys) => {
        for(let k of keys) {
            if (obj[k] !== undefined) return obj[k];
            const lowerKey = Object.keys(obj).find(ok => ok.toLowerCase() === k.toLowerCase());
            if (lowerKey && obj[lowerKey] !== undefined) return obj[lowerKey];
        }
        return null;
    };
    return {
        gid: getVal(row, ['gid', 'id', 'ogc_fid', 'objectid']),
        sothua: getVal(row, ['sothua', 'so_thua', 'shthua', 'parcel_no', 'sothutu', 'sh_thua', 'thua', 'so_hieu_thua']) || '',
        sodoto: getVal(row, ['sodoto', 'so_to', 'shmap', 'map_sheet', 'sohieutoba', 'sh_map', 'to_ban_do', 'so_hieu_to_ban_do']) || '',
        tenchu: getVal(row, ['tenchu', 'ten_chu', 'owner', 'chu_so_huu', 'chusohuu', 'chu', 'ho_ten', 'name']) || '',
        diachi: getVal(row, ['diachi', 'dia_chi', 'address', 'khu_vuc', 'vi_tri', 'dia_chi_thua_dat']) || '',
        dientich: getVal(row, ['dientich', 'dien_tich', 'area', 'shape_area', 'shape_starea', 'dt', 'dien_tich_phap_ly']),
        // FIX: Add explicit mapping for landType (loaidat)
        loaidat: getVal(row, ['loaidat', 'loai_dat', 'kh', 'mdsd', 'muc_dich', 'ma_loai_dat', 'kyhieumucd']),
        geometry: JSON.parse(row.geojson || '{}'), 
        ...row
    };
};

// Dynamic CRUD for Spatial Tables (Catch-all route defined LAST)
app.get('/api/:tableName', async (req, res) => {
    try {
        const { tableName } = req.params;
        // Avoid handling specific API routes if they accidentally fell through
        if (tableName === 'spatial-tables') {
            const r = await pool.query(`SELECT table_name, display_name FROM spatial_tables_registry ORDER BY created_at DESC`);
            return res.json(r.rows);
        }

        const safeNameInput = tableName.toLowerCase().replace(/[^a-z0-9_]/g, '');
        let safeName = safeNameInput;

        // --- ENHANCED TABLE LOOKUP (Case-Insensitive) ---
        const client = await pool.connect();
        try {
            const check = await client.query(`SELECT table_name FROM information_schema.tables WHERE lower(table_name) = $1 LIMIT 1`, [safeNameInput]);
            if (check.rows.length > 0) {
                safeName = check.rows[0].table_name;
            }
        } finally {
            client.release();
        }

        const colsRes = await pool.query(`SELECT column_name FROM information_schema.columns WHERE table_name = $1`, [safeName]);
        const cols = colsRes.rows.map(r => r.column_name); // Keep original case

        // Helper to match column case-insensitive
        const findCol = (target) => {
            return cols.find(c => c.toLowerCase() === target.toLowerCase()) || null;
        };

        const colMap = (target) => {
             const variations = {
                 'sothua': ['sothua', 'so_thua', 'shthua', 'parcel_no', 'sothutu', 'sh_thua', 'thua', 'so_hieu_thua'],
                 'sodoto': ['sodoto', 'so_to', 'shmap', 'map_sheet', 'sohieutoba', 'sh_map', 'to_ban_do', 'so_hieu_to_ban_do'],
                 'tenchu': ['tenchu', 'ten_chu', 'owner', 'chu_so_huu', 'chusohuu', 'chu', 'ho_ten', 'name'],
                 'diachi': ['diachi', 'dia_chi', 'address', 'khu_vuc', 'vi_tri', 'dia_chi_thua_dat'],
                 'dientich': ['dientich', 'dien_tich', 'area', 'shape_area', 'shape_starea', 'dt', 'dien_tich_phap_ly'],
                 'loaidat': ['loaidat', 'loai_dat', 'kh', 'mdsd', 'muc_dich', 'ma_loai_dat', 'kyhieumucd'],
                 'properties': ['properties']
             };
             let match = findCol(target);
             if (match) return `"${match}"`;
             if (variations[target]) {
                 for (const v of variations[target]) {
                     match = findCol(v);
                     if (match) return `"${match}"`;
                 }
             }
             return null;
        };

        let geomCol = findCol('geometry') || findCol('geom') || findCol('the_geom') || findCol('shape');

        // --- HANDLE VN-2000 (9210) AND UNKNOWN (0) SRID ---
        const geomQuery = geomCol 
            ? `ST_AsGeoJSON(ST_Transform(ST_SetSRID("${geomCol}", CASE WHEN ST_SRID("${geomCol}") = 0 THEN 9210 ELSE ST_SRID("${geomCol}") END), 4326)) as geojson` 
            : 'NULL as geojson';

        let gidCol = findCol('gid') ? `"${findCol('gid')}"` : (findCol('id') ? `"${findCol('id')}" as gid` : (findCol('ogc_fid') ? `"${findCol('ogc_fid')}" as gid` : 'NULL as gid'));

        // --- SERVER-SIDE FILTERING LOGIC ---
        const { sothua, sodoto, tenchu, diachi } = req.query;
        let whereClauses = [];
        let params = [];
        let paramIdx = 1;

        if (sothua) {
            const col = colMap('sothua');
            // EXACT MATCH (Case-Insensitive for alphanumeric parcel numbers)
            if (col) { whereClauses.push(`LOWER(TRIM(${col}::text)) = LOWER($${paramIdx++})`); params.push(String(sothua).trim()); }
        }
        if (sodoto) {
            const col = colMap('sodoto');
            // EXACT MATCH (Case-Insensitive)
            if (col) { whereClauses.push(`LOWER(TRIM(${col}::text)) = LOWER($${paramIdx++})`); params.push(String(sodoto).trim()); }
        }
        if (tenchu) {
            const col = colMap('tenchu');
            // LIKE MATCH (ILIKE)
            if (col) { whereClauses.push(`${col}::text ILIKE $${paramIdx++}`); params.push(`%${tenchu}%`); }
        }
        if (diachi) {
            const col = colMap('diachi');
            // LIKE MATCH (ILIKE)
            if (col) { whereClauses.push(`${col}::text ILIKE $${paramIdx++}`); params.push(`%${diachi}%`); }
        }

        // --- OPTIMIZATION: If no filters, limit results to prevent lag ---
        let limitClause = 'LIMIT 50000';
        if (whereClauses.length === 0) {
            limitClause = 'LIMIT 20';
        }

        const whereSQL = whereClauses.length > 0 ? `WHERE ${whereClauses.join(' AND ')}` : '';

        // Helper for SELECT aliases
        const selMap = (target) => {
             const col = colMap(target);
             return col ? `${col} as ${target}` : `NULL as ${target}`;
        }

        const query = `
            SELECT 
                ${gidCol},
                ${selMap('sothua')},
                ${selMap('sodoto')},
                ${selMap('tenchu')},
                ${selMap('diachi')},
                ${selMap('dientich')},
                ${selMap('loaidat')},
                ${selMap('properties')},
                ${geomQuery}
            FROM "${safeName}"
            ${whereSQL}
            ORDER BY ${gidCol.includes('as gid') ? 'gid' : gidCol} DESC
            ${limitClause}
        `;        
        const r = await pool.query(query, params);
        res.json(r.rows.map(mapRowToParcel));
    } catch(e) { 
        res.status(500).json({error: e.message}); 
    }
});

