        } finally {
            setIsBackingUp(false);
        }
    };

    const handleRestoreDatabase = async (e: React.ChangeEvent<HTMLInputElement>) => {
        const file = e.target.files?.[0];
        if (!file) return;

        if (!confirm(`CẢNH BÁO: Hành động này sẽ GHI ĐÈ dữ liệu hiện tại bằng file backup '${file.name}'. Bạn có chắc chắn muốn tiếp tục không?`)) {
            e.target.value = ''; // Reset input
            return;
        }

        try {
            setIsRestoring(true);
            await adminService.restoreDatabase(file);
            alert("Phục hồi cơ sở dữ liệu thành công! Trang web sẽ tải lại.");
            window.location.reload();
        } catch (err: any) {
            alert("Phục hồi thất bại: " + err.message);
        } finally {
            setIsRestoring(false);
            if (restoreInputRef.current) restoreInputRef.current.value = '';
        }
    };

    const formatBytes = (bytes: number) => {
        if (bytes === 0) return '0 Bytes';
        const k = 1024;
        const sizes = ['Bytes', 'KB', 'MB', 'GB', 'TB'];
        const i = Math.floor(Math.log(bytes) / Math.log(k));
        return parseFloat((bytes / Math.pow(k, i)).toFixed(2)) + ' ' + sizes[i];
    };

