const hostname = window.location.hostname;
const isLocal = hostname === 'localhost' || hostname === '127.0.0.1' || hostname.startsWith('192.168.');

// Nếu Local -> Port 3004. Nếu Server -> HTTPS Default (443)
const API_URL = isLocal 
    ? `http://${hostname}:3004` 
    : 'https://apigeo.gisvn.space';

// DTO: Data Transfer Object cho Thửa đất dạng bảng
export interface ParcelDTO {
    gid?: number; 
    sothua: string;
    sodoto: string;
    tenchu?: string;
    diachi?: string;
    loaidat?: string; // Trường mục đích sử dụng đất
    dientich?: number;
    geometry?: any; // Add geometry field
    file?: File | null; 
    [key: string]: any; 
}

export interface SpatialTable {
    table_name: string;
    display_name: string;
}

// Helper để xử lý Circular JSON
const safeStringify = (obj: any) => {
    const seen = new WeakSet();
    try {
        return JSON.stringify(obj, (key, value) => {
            if (typeof value === "object" && value !== null) {
                if (seen.has(value)) return;
                seen.add(value);
            }
            return value;
        });
    } catch (e) {
        return "{}";
    }
};

// --- NEW: Helper to get Auth Headers for Logging ---
const getAuthHeaders = () => {
    const headers: any = {};
    const userStr = localStorage.getItem('geo_user');
    if (userStr) {
        try {
            const u = JSON.parse(userStr);
            headers['x-user-id'] = u.id;
            headers['x-user-name'] = encodeURIComponent(u.name);
            headers['x-branch-id'] = u.branchId;
        } catch (e) {}
    }
    return headers;
};

const handleResponse = async (res: Response) => {
    if (!res.ok) {
        const errorText = await res.text();
        throw new Error(`Lỗi API (${res.status}): ${errorText || res.statusText}`);
    }
    return res.json();
};

export const parcelApi = {
    // GET with Server-side Filtering
    getAll: async (layer: string, filters?: { sodoto?: string, sothua?: string, tenchu?: string, diachi?: string }) => {
        let queryString = `?t=${Date.now()}`;
        if (filters) {
            if (filters.sodoto) queryString += `&sodoto=${encodeURIComponent(filters.sodoto)}`;
            if (filters.sothua) queryString += `&sothua=${encodeURIComponent(filters.sothua)}`;
            if (filters.tenchu) queryString += `&tenchu=${encodeURIComponent(filters.tenchu)}`;
            if (filters.diachi) queryString += `&diachi=${encodeURIComponent(filters.diachi)}`;
        }

        const res = await fetch(`${API_URL}/api/${layer}${queryString}`, {
             headers: { ...getAuthHeaders() }
        });
        return await handleResponse(res);
    },

    // POST (JSON thường)
    create: async (layer: string, data: ParcelDTO) => {
        const res = await fetch(`${API_URL}/api/${layer}`, {
            method: 'POST',
            headers: { 
                'Content-Type': 'application/json',
                ...getAuthHeaders() 
            },
            body: safeStringify(data)
        });
        return await handleResponse(res);
    },

    // POST (Multipart Form Data - Upload File)
    createWithUpload: async (layer: string, data: ParcelDTO) => {
        const formData = new FormData();
        formData.append('sothua', data.sothua);
        formData.append('sodoto', data.sodoto);
        if (data.tenchu) formData.append('tenchu', data.tenchu);
        if (data.diachi) formData.append('diachi', data.diachi);
        if (data.loaidat) formData.append('loaidat', data.loaidat);
        if (data.file) formData.append('file', data.file);

        const res = await fetch(`${API_URL}/api/${layer}/upload`, {
            method: 'POST',
            // Note: Do NOT set Content-Type for FormData, browser sets it with boundary
            headers: { ...getAuthHeaders() }, 
            body: formData
        });
        return await handleResponse(res);
    },

    // PUT (JSON thường)
    update: async (layer: string, gid: number, data: ParcelDTO) => {
        const res = await fetch(`${API_URL}/api/${layer}/${gid}`, {
            method: 'PUT',
            headers: { 
                'Content-Type': 'application/json',
                ...getAuthHeaders()
            },
            body: safeStringify(data)
        });
        return await handleResponse(res);
    },

    // PUT (Multipart Form Data - Update with File)
    updateWithUpload: async (layer: string, gid: number, data: ParcelDTO) => {
        const formData = new FormData();
        formData.append('sothua', data.sothua);
        formData.append('sodoto', data.sodoto);
        if (data.tenchu) formData.append('tenchu', data.tenchu);
        if (data.diachi) formData.append('diachi', data.diachi);
        if (data.loaidat) formData.append('loaidat', data.loaidat);
        if (data.file) formData.append('file', data.file);

        const res = await fetch(`${API_URL}/api/${layer}/${gid}/upload`, {
            method: 'PUT',
            headers: { ...getAuthHeaders() },
            body: formData
        });
        return await handleResponse(res);
    },

    // DELETE
    delete: async (layer: string, gid: number) => {
        const res = await fetch(`${API_URL}/api/${layer}/${gid}`, {
            method: 'DELETE',
            headers: { ...getAuthHeaders() }
        });
        return await handleResponse(res);
    },

    // INTERNAL TABLE MANAGEMENT
    manageTables: {
        getAll: async (): Promise<SpatialTable[]> => {
            const res = await fetch(`${API_URL}/api/spatial-tables`, { headers: getAuthHeaders() });
            return await handleResponse(res);
        },
        create: async (tableName: string, displayName?: string) => {
            const res = await fetch(`${API_URL}/api/spatial-tables`, {
                method: 'POST',
                headers: { 'Content-Type': 'application/json', ...getAuthHeaders() },
                body: safeStringify({ tableName, displayName })
            });
            return await handleResponse(res);
        },
        link: async (tableName: string, displayName?: string) => {
             const res = await fetch(`${API_URL}/api/spatial-tables/link`, {
                method: 'POST',
                headers: { 'Content-Type': 'application/json', ...getAuthHeaders() },
                body: safeStringify({ tableName, displayName })
            });
            return await handleResponse(res);
        },
        unlink: async (tableName: string) => {
            const res = await fetch(`${API_URL}/api/spatial-tables/unlink`, {
               method: 'POST',
               headers: { 'Content-Type': 'application/json', ...getAuthHeaders() },
               body: safeStringify({ tableName })
           });
           return await handleResponse(res);
        },
        rename: async (oldName: string, newName?: string, displayName?: string) => {
             const res = await fetch(`${API_URL}/api/spatial-tables/${oldName}`, {
                method: 'PUT',
                headers: { 'Content-Type': 'application/json', ...getAuthHeaders() },
                body: safeStringify({ newName, displayName })
            });
            return await handleResponse(res);
        },
        delete: async (tableName: string) => {
            const res = await fetch(`${API_URL}/api/spatial-tables/${tableName}`, {
                method: 'DELETE',
                headers: { ...getAuthHeaders() }
            });
            return await handleResponse(res);
        }
    }
};

