                            <FileUp size={16} /> 
                            {editingId ? 'Cập nhật Shapefile (Tùy chọn)' : 'Upload Shapefile (.zip)'}
                            <span className="text-[10px] normal-case bg-blue-900 text-blue-200 px-2 rounded-full">
                                {editingId ? 'Thay thế hình học & Tính lại diện tích' : 'Tự động tính diện tích'}
                            </span>
                         </label>
                         <input 
                            id="file-upload"
                            type="file" 
                            accept=".zip"
                            onChange={handleFileChange}
                            className="block w-full text-sm text-gray-400 file:mr-4 file:py-2 file:px-4 file:rounded-full file:border-0 file:text-sm file:font-semibold file:bg-blue-600 file:text-white hover:file:bg-blue-500 cursor-pointer"
                         />
                    </div>

                    <div className="flex gap-3 justify-end mt-2">
                        {editingId && (
                            <button type="button" onClick={resetForm} className="bg-gray-700 hover:bg-gray-600 text-white px-4 py-2 rounded-lg flex items-center gap-2 transition-colors">
                                <X size={18} /> Hủy
                            </button>
                        )}
                        <button type="submit" className={`px-6 py-2 rounded-lg flex items-center justify-center gap-2 font-bold text-white shadow-lg transition-all ${editingId ? 'bg-orange-600 hover:bg-orange-500' : 'bg-blue-600 hover:bg-blue-500'}`}>
                            {editingId ? <Save size={18} /> : <Plus size={18} />}
                            {editingId ? 'Lưu thay đổi' : 'Thêm mới'}
                        </button>
                    </div>
                </form>
            </div>

            {/* DATA TABLE */}
            <div className="bg-gray-800 rounded-xl border border-gray-700 overflow-hidden shadow-xl">
                {/* Table Header */}
                <div className="grid grid-cols-12 bg-gray-900 text-gray-400 text-xs uppercase font-bold py-3 px-4 border-b border-gray-700 tracking-wider">
                    <div className="col-span-1">GID</div>
                    <div className="col-span-1">Số Tờ</div>
                    <div className="col-span-1">Số Thửa</div>
                    <div className="col-span-3">Chủ sở hữu</div>
                    <div className="col-span-2">Mục đích</div>
                    <div className="col-span-2 text-right">Diện tích (m²)</div>
                    <div className="col-span-2 text-right">Thao tác</div>
                </div>

                {/* Table Body */}
                {loading ? (
                    <div className="p-12 flex justify-center items-center text-blue-400 flex-col gap-3">
                        <RefreshCw className="animate-spin w-8 h-8"/>
                        <span>Đang truy vấn dữ liệu từ máy chủ...</span>
                    </div>
                ) : parcels.length === 0 ? (
                    <div className="p-16 text-center text-gray-500 flex flex-col items-center gap-3">
                        <Search size={48} className="text-gray-700" />
                        <p className="font-medium">Chưa có dữ liệu hiển thị</p>
                        <p className="text-sm">Vui lòng nhập thông tin tìm kiếm hoặc nhấn nút "Tìm kiếm Dữ liệu" để tải danh sách.</p>
                    </div>
                ) : (
                    <div className="max-h-[600px] overflow-y-auto custom-scrollbar">
                        {parcels.map((p) => (
                            <div key={p.gid} className={`grid grid-cols-12 py-3 px-4 items-center border-b border-gray-700/50 hover:bg-gray-700/50 transition-colors group ${editingId === p.gid ? 'bg-orange-900/20 border-l-4 border-orange-500 pl-3' : ''}`}>
                                <div className="col-span-1 font-mono text-xs text-gray-500">#{p.gid}</div>
                                <div className="col-span-1 font-bold text-white">{p.sodoto || '--'}</div>
                                <div className="col-span-1 font-bold text-blue-400">{p.sothua || '--'}</div>
                                <div className="col-span-3 text-gray-300 truncate pr-2" title={p.tenchu}>{p.tenchu || '--'}</div>
                                <div className="col-span-2"><span className="bg-gray-900 px-2 py-1 rounded text-xs font-bold text-blue-300 border border-gray-700">{p.loaidat || '--'}</span></div>
                                <div className="col-span-2 text-right font-mono text-green-400">
                                    {p.dientich ? Math.round(Number(p.dientich)).toLocaleString() : '--'}
                                </div>
                                <div className="col-span-2 text-right flex justify-end gap-2 opacity-60 group-hover:opacity-100 transition-opacity">
                                    <button onClick={() => handleEdit(p)} className="bg-blue-600/20 text-blue-400 hover:bg-blue-600 hover:text-white p-1.5 rounded transition-colors"><Edit size={16} /></button>
                                    <button onClick={() => handleDelete(p.gid!)} className="bg-red-600/20 text-red-400 hover:bg-red-600 hover:text-white p-1.5 rounded transition-colors"><Trash2 size={16} /></button>
                                </div>
                            </div>
                        ))}
                    </div>
                )}
            </div>
        </div>
    );
};

export default ParcelManager;

import React, { useEffect, useRef, useState } from 'react';
import { User, LandParcel, UserRole, WMSLayerConfig } from '../types';
import { gisService, API_URL } from '../services/mockBackend';
import { parcelApi } from '../services/parcelApi';
import { Layers, MousePointer2, Save, Trash2, X, AlertTriangle, CheckCircle, MapPin, Globe, Map as MapIcon, Eye, EyeOff, Info, List, FileText, WifiOff, RefreshCw, Search, Loader2, Printer, Navigation, Crosshair, ChevronDown, Table as TableIcon, User as UserIcon, Ruler, Tag, MousePointerClick, Filter, HelpCircle, Square, Database, Edit } from 'lucide-react';
import { jsPDF } from "jspdf";
import html2canvas from "html2canvas";
import proj4 from "proj4";

// OpenLayers uses global 'ol' from CDN
declare const ol: any;

// --- CẤU HÌNH HỆ TỌA ĐỘ VN-2000 ---
proj4.defs("EPSG:9210", "+proj=tmerc +lat_0=0 +lon_0=105.75 +k=0.9999 +x_0=500000 +y_0=0 +ellps=WGS84 +towgs84=-191.90441429,-39.30318279,-111.45032835,0.00928836,0.01975479,-0.00427372,0.252906278 +units=m +no_defs");

interface MapPageProps {
  user: User | null;
  systemSettings?: Record<string, string>;
}

const MapPage: React.FC<MapPageProps> = ({ user, systemSettings }) => {
  const mapElement = useRef<HTMLDivElement>(null);
  const mapInstance = useRef<any>(null);
  const popupElement = useRef<HTMLDivElement>(null);
  const popupOverlay = useRef<any>(null);

  // Layer Refs
  const osmLayer = useRef<any>(null);
  const googleLayer = useRef<any>(null);
  const vietbandoLayer = useRef<any>(null);
  const wmsLayerGroup = useRef<any>(null);
  const vectorLayer = useRef<any>(null); 
  const highlightLayer = useRef<any>(null); 

  // Measure Refs
  const drawSource = useRef<any>(new ol.source.Vector());
  const drawLayer = useRef<any>(null);
  const drawInteraction = useRef<any>(null);
  const measureTooltips = useRef<any[]>([]); 

  // State
  const [selectedParcel, setSelectedParcel] = useState<LandParcel | null>(null);
  const [isEditing, setIsEditing] = useState(false); // Mode selected
  const [isPopupEditing, setIsPopupEditing] = useState(false); // Mode form edit attributes
  const [formData, setFormData] = useState<any>({});

  // Search State
  const [spatialTables, setSpatialTables] = useState<any[]>([]);
  const [searchForm, setSearchForm] = useState({
      table: 'ALL',
      soTo: '',
      soThua: '',
      owner: ''
  });
  const [searchResults, setSearchResults] = useState<LandParcel[]>([]);
  const [isSearching, setIsSearching] = useState(false);
  const [isSearchOpen, setIsSearchOpen] = useState(false);

  // Layer Control State
  const [activeBaseLayer, setActiveBaseLayer] = useState<'OSM' | 'GOOGLE' | 'VIETBANDO'>('OSM');
  const [availableLayers, setAvailableLayers] = useState<WMSLayerConfig[]>([]);
  const [visibleLayerIds, setVisibleLayerIds] = useState<string[]>([]);
  const [activeLayerId, setActiveLayerId] = useState<string | null>(null);
  const [isLayerMenuOpen, setIsLayerMenuOpen] = useState(false);

  const [isGeneratingPDF, setIsGeneratingPDF] = useState(false);
  const [isSaving, setIsSaving] = useState(false);
  const [isLocating, setIsLocating] = useState(false);
  const [isFetchingInfo, setIsFetchingInfo] = useState(false);
  const [fetchError, setFetchError] = useState<string | null>(null);

  const [mouseCoords, setMouseCoords] = useState<{lon: string, lat: string} | null>(null);
  const [measureMode, setMeasureMode] = useState<'LineString' | 'Polygon' | null>(null);

  const printTemplateRef = useRef<HTMLDivElement>(null);
  const parcelCanvasRef = useRef<HTMLCanvasElement>(null);
  const [geometryPoints, setGeometryPoints] = useState<any[]>([]);

  useEffect(() => {
      const initData = async () => {
          try {
              const layers = await gisService.getLayers();
              setAvailableLayers(layers);
              const defaults = layers.filter(l => l.visible).map(l => l.id);
              setVisibleLayerIds(defaults);
              if (layers.length > 0) setActiveLayerId(layers[0].id);

              const tables = await gisService.getSpatialTables();
              setSpatialTables(tables);
          } catch (e) { console.error("Failed to load initial data", e); }
      };
      initData();
  }, []);

  useEffect(() => {
      if (!mapElement.current || mapInstance.current) return;
      if (typeof ol === 'undefined') return;

      osmLayer.current = new ol.layer.Tile({ source: new ol.source.OSM(), visible: true, properties: { id: 'OSM' } });
      googleLayer.current = new ol.layer.Tile({ source: new ol.source.XYZ({ url: 'https://mt1.google.com/vt/lyrs=y&x={x}&y={y}&z={z}' }), visible: false, properties: { id: 'GOOGLE' } });
      vietbandoLayer.current = new ol.layer.Tile({ source: new ol.source.XYZ({ url: `${API_URL}/api/proxy/vietbando?z={z}&x={x}&y={y}` }), visible: false, properties: { id: 'VIETBANDO' } });
      wmsLayerGroup.current = new ol.layer.Group({ layers: [], zIndex: 10 });
      vectorLayer.current = new ol.layer.Vector({ source: new ol.source.Vector(), style: new ol.style.Style({ stroke: null, fill: null }), visible: false, zIndex: 20 });
      drawLayer.current = new ol.layer.Vector({ source: drawSource.current, style: new ol.style.Style({ fill: new ol.style.Fill({ color: 'rgba(255, 255, 255, 0.2)' }), stroke: new ol.style.Stroke({ color: '#ffcc33', width: 2 }) }), zIndex: 101 });
      highlightLayer.current = new ol.layer.Vector({ source: new ol.source.Vector(), style: new ol.style.Style({ stroke: new ol.style.Stroke({ color: '#ef4444', width: 3 }), fill: new ol.style.Fill({ color: 'rgba(239, 68, 68, 0.1)' }) }), zIndex: 100 });

      const map = new ol.Map({
          target: mapElement.current,
          layers: [osmLayer.current, googleLayer.current, vietbandoLayer.current, wmsLayerGroup.current, drawLayer.current, highlightLayer.current],
          view: new ol.View({ center: ol.proj.fromLonLat([106.619, 11.284]), zoom: 13 }),
          controls: ol.control.defaults.defaults({ zoom: true, rotate: false, attribution: false })
      });

      popupOverlay.current = new ol.Overlay({ element: popupElement.current, autoPan: { animation: { duration: 250 } }, positioning: 'bottom-center', offset: [0, -10] });
      map.addOverlay(popupOverlay.current);

      map.on('pointermove', (evt: any) => {
          if (evt.dragging) return;
          const coords = ol.proj.toLonLat(evt.coordinate);
          setMouseCoords({ lon: coords[0].toFixed(6), lat: coords[1].toFixed(6) });
      });

      map.on('singleclick', async (evt: any) => {
          if (drawInteraction.current) return;
          await identifyFeature(evt.coordinate);
      });

      mapInstance.current = map;
      return () => { map.setTarget(undefined); mapInstance.current = null; };
  }, []);

  useEffect(() => {
      if (!mapInstance.current) return;
      osmLayer.current.setVisible(activeBaseLayer === 'OSM');
      googleLayer.current.setVisible(activeBaseLayer === 'GOOGLE');
      vietbandoLayer.current.setVisible(activeBaseLayer === 'VIETBANDO');
  }, [activeBaseLayer]);

  useEffect(() => {
      if (!mapInstance.current || !wmsLayerGroup.current) return;
      wmsLayerGroup.current.getLayers().clear();
      availableLayers.forEach(config => {
          const isActive = config.id === activeLayerId;
          const isVisible = visibleLayerIds.includes(config.id);
          if (isVisible) {
              const layer = new ol.layer.Tile({
                  source: new ol.source.TileWMS({
                      url: config.url,
                      params: { 'LAYERS': config.layers, 'TILED': true, 'VERSION': '1.1.1', 'FORMAT': 'image/png', 'TRANSPARENT': true },
                      serverType: 'geoserver', transition: 0
                  }),
                  visible: true,
                  properties: { config: config, isActive: isActive },
                  zIndex: isActive ? 100 : 10
              });
              wmsLayerGroup.current.getLayers().push(layer);
          }
      });
  }, [availableLayers, visibleLayerIds, activeLayerId]);

  useEffect(() => {
    if (geometryPoints.length === 0 || !parcelCanvasRef.current) return;
    const canvas = parcelCanvasRef.current;
    const ctx = canvas.getContext('2d');
    if (!ctx) return;
    ctx.clearRect(0, 0, canvas.width, canvas.height);
    ctx.fillStyle = '#ffffff';
    ctx.fillRect(0, 0, canvas.width, canvas.height);
    const points = geometryPoints;
    const xs = points.map(p => p.x);
    const ys = points.map(p => p.y);
    const minX = Math.min(...xs);
    const maxX = Math.max(...xs);
    const minY = Math.min(...ys);
    const maxY = Math.max(...ys);
    const width = maxX - minX;
    const height = maxY - minY;
    const padding = 60;
    const availWidth = canvas.width - padding * 2;
    const availHeight = canvas.height - padding * 2;
    const scale = Math.min(width === 0 ? 1 : availWidth / width, height === 0 ? 1 : availHeight / height);
    const toCanvasX = (mapX: number) => (mapX - minX) * scale + padding + (availWidth - width * scale)/2;
    const toCanvasY = (mapY: number) => canvas.height - ((mapY - minY) * scale + padding) - (availHeight - height * scale)/2;
    ctx.beginPath();
    ctx.lineWidth = 2;
    ctx.strokeStyle = '#000000';
    points.forEach((p, i) => {
        const drawX = toCanvasX(p.x);
        const drawY = toCanvasY(p.y);
        if (i === 0) ctx.moveTo(drawX, drawY);
        else ctx.lineTo(drawX, drawY);
    });
    ctx.closePath();
    ctx.stroke();
    points.forEach((p, i) => {
        const drawX = toCanvasX(p.x);
        const drawY = toCanvasY(p.y);
        ctx.beginPath();
        ctx.arc(drawX, drawY, 3, 0, 2 * Math.PI);
        ctx.fillStyle = "#000000"; 
        ctx.fill();
        ctx.font = "bold 14px Times New Roman";
        ctx.textAlign = "center";
        ctx.fillText(String(p.id), drawX, drawY - 8);
    });
  }, [geometryPoints]);

  const identifyFeature = async (coordinate: number[]) => {
      if (!mapInstance.current || !wmsLayerGroup.current) return;
      setFetchError(null);
      setIsPopupEditing(false);
      const layers = wmsLayerGroup.current.getLayers().getArray();
      let targetLayer = layers.find((l:any) => l.get('isActive') === true && l.getVisible()) || layers.findLast((l:any) => l.getVisible());

      if (!targetLayer) {
          setIsEditing(false); setSelectedParcel(null);
          popupOverlay.current.setPosition(undefined);
          highlightLayer.current.getSource().clear();
          return;
      }

      const targetSource = targetLayer.getSource();
      if (!targetSource) return;

      document.body.style.cursor = 'wait';
      setIsFetchingInfo(true);

      const url = targetSource.getFeatureInfoUrl(coordinate, mapInstance.current.getView().getResolution(), mapInstance.current.getView().getProjection(), { 'INFO_FORMAT': 'application/json', 'FEATURE_COUNT': 1 });

      if (url) {
           try {
               const res = await fetch(`${API_URL}/api/proxy/forward?url=${encodeURIComponent(url)}`);
               if (!res.ok) throw new Error(`HTTP Error ${res.status}`);
               const data = await res.json();
               if (data.features && data.features.length > 0) {
                   const feature = data.features[0];
                   const props = feature.properties || {};
                   const getAttr = (keys: string[]) => {
                       for (const k of keys) {
                           if (props[k] !== undefined && props[k] !== null) return props[k];
                           const lower = Object.keys(props).find(pk => pk.toLowerCase() === k.toLowerCase());
                           if (lower) return props[lower];
                       }
                       return null;
                   };

                   const mappedParcel: LandParcel = {
                       id: feature.id || `wms-${Date.now()}`,
                       geometry: feature.geometry,
                       properties: {
                            gid: props.gid || feature.id?.split('.').pop(),
                            ownerName: getAttr(['tenchu', 'chu', 'owner', 'chusohuu', 'ten_chu']) || 'Chưa cập nhật',
                            landType: getAttr(['loaidat', 'kyhieumucd', 'loai_dat', 'mdsd']) || 'Chưa xác định',
                            area: Number(getAttr(['dientich', 'dien_tich', 'shape_area', 'area'])) || 0,
                            so_to: getAttr(['sohieutoba', 'sodoto', 'shmap', 'so_to', 'map_sheet']),
                            so_thua: getAttr(['sothututhu', 'sothua', 'shthua', 'so_thua', 'parcel_no']),
                            address: getAttr(['diachi', 'dia_chi', 'address', 'khu_vuc']),
                            tableName: targetLayer.get('config')?.layers?.split(':').pop() || 'parcels',
                            tableDisplayName: targetLayer.get('config')?.name || 'Lớp WMS',
                            ...props 
                       }
                   };

                   const olFeature = (new ol.format.GeoJSON()).readFeature(feature); 
                   highlightLayer.current.getSource().clear(); 
                   highlightLayer.current.getSource().addFeature(olFeature);
                   handleSelectParcel(mappedParcel);
                   popupOverlay.current.setPosition(coordinate);
               } else {
                   setIsEditing(false); setSelectedParcel(null);
                   popupOverlay.current.setPosition(undefined);
                   highlightLayer.current.getSource().clear();
               }
           } catch (err) { setFetchError("Không lấy được dữ liệu từ lớp bản đồ (WMS)."); }
           finally { setIsFetchingInfo(false); document.body.style.cursor = 'default'; }
      } else { setIsFetchingInfo(false); document.body.style.cursor = 'default'; }
  };

  const handleSelectParcel = (parcel: LandParcel) => {
      setSelectedParcel(parcel);
      setFormData(parcel.properties);
      setIsEditing(true);
      if (popupElement.current) popupElement.current.style.display = 'block';
  };

  const handleSaveAttributes = async () => {
    if (!formData.tableName || !formData.gid) {
        alert("Không xác định được bảng hoặc ID để cập nhật.");
        return;
    }
    setIsSaving(true);
    try {
        const updatePayload = {
            sodoto: formData.so_to,
            sothua: formData.so_thua,
            tenchu: formData.ownerName,
            diachi: formData.address,
            loaidat: formData.landType
        };
        await parcelApi.update(formData.tableName, formData.gid, updatePayload as any);
        alert("Cập nhật thông tin thành công!");
        setIsPopupEditing(false);
    } catch (err: any) {
        alert("Lỗi lưu dữ liệu: " + err.message);
    } finally {
        setIsSaving(false);
    }
  };

  const handleLocateMe = () => {
      setIsLocating(true);
      if (!navigator.geolocation) { alert("Không hỗ trợ GPS."); setIsLocating(false); return; }
      navigator.geolocation.getCurrentPosition((pos) => {
          const coords = ol.proj.fromLonLat([pos.coords.longitude, pos.coords.latitude]);
          mapInstance.current.getView().animate({ center: coords, zoom: 17, duration: 1000 });
          const marker = new ol.Feature(new ol.geom.Point(coords));
          marker.setStyle(new ol.style.Style({ image: new ol.style.Circle({ radius: 8, fill: new ol.style.Fill({color: '#3b82f6'}), stroke: new ol.style.Stroke({color: '#fff', width: 2}) }) }));
          highlightLayer.current.getSource().addFeature(marker);
          setIsLocating(false);
      }, () => { alert("Không thể lấy vị trí."); setIsLocating(false); });
  };

  const clearMeasurement = () => {
      drawSource.current.clear();
      measureTooltips.current.forEach(tooltip => mapInstance.current.removeOverlay(tooltip));
      measureTooltips.current = [];
      if (drawInteraction.current) { mapInstance.current.removeInteraction(drawInteraction.current); drawInteraction.current = null; }
      setMeasureMode(null);
  };

  const handleSearch = async (e: React.FormEvent) => {
      e.preventDefault();
      if (!searchForm.soTo && !searchForm.soThua && !searchForm.owner) return;
      setIsSearching(true); setSearchResults([]); 
      try {
          const filters = { sodoto: searchForm.soTo.trim(), sothua: searchForm.soThua.trim(), tenchu: searchForm.owner.trim() };
          let allResults: LandParcel[] = [];
          if (searchForm.table === 'ALL' || !searchForm.table) {
              const tablesToSearch = spatialTables.length > 0 ? spatialTables.map((t: any) => t.table_name) : ['parcels'];
              const resultsArray = await Promise.all(tablesToSearch.map(t => gisService.searchParcels(t, filters).then(res => res.map(item => ({...item, properties: {...item.properties, tableName: t }}))).catch(() => [])));
              resultsArray.forEach(res => { allResults = [...allResults, ...res]; });
          } else {
              const res = await gisService.searchParcels(searchForm.table, filters);
              allResults = res.map(item => ({...item, properties: {...item.properties, tableName: searchForm.table }}));
          }
          setSearchResults(allResults);
          if (allResults.length === 0) alert('Không tìm thấy kết quả nào.');
      } catch (err) { alert("Lỗi tìm kiếm: " + (err as Error).message); } finally { setIsSearching(false); }
  };

  const handleSelectSearchResult = async (parcel: LandParcel) => {
      handleSelectParcel(parcel); setIsSearchOpen(false);
      if (!parcel.geometry) { alert("Thửa đất này chưa có dữ liệu hình học."); return; }
      try {
           const format = new ol.format.GeoJSON();
           const geom = format.readGeometry(parcel.geometry, { dataProjection: 'EPSG:4326', featureProjection: 'EPSG:3857' });
           if (geom) {
               highlightLayer.current.getSource().clear(); 
               highlightLayer.current.getSource().addFeature(new ol.Feature({ geometry: geom, ...parcel.properties }));
               const extent = geom.getExtent();
               mapInstance.current.getView().fit(extent, { padding: [100, 100, 100, 100], duration: 1000, maxZoom: 19 });
               popupOverlay.current.setPosition(ol.extent.getCenter(extent));
           }
      } catch (e) { console.error("Error displaying feature:", e); }
  };

  const getAttribute = (obj: any, keys: string[]) => {
      if (!obj) return '';
      for (const k of keys) {
          if (obj[k] !== undefined && obj[k] !== null) return obj[k];
          const lowerKey = Object.keys(obj).find(pk => pk.toLowerCase() === k.toLowerCase());
          if (lowerKey) return obj[lowerKey];
      }
      return '';
  };

  const handleExportPDF = async () => {
      if (!selectedParcel || !selectedParcel.geometry) { alert("Vui lòng chọn một thửa đất."); return; }
      setIsGeneratingPDF(true);
      try {
          const feature = (new ol.format.GeoJSON()).readFeature({ type: "Feature", geometry: selectedParcel.geometry }, { dataProjection: 'EPSG:4326', featureProjection: 'EPSG:3857' });
          const geom = feature.getGeometry();
          if (!geom) throw new Error("Không tìm thấy hình học.");
          const geomTransformed = geom.clone().transform('EPSG:3857', 'EPSG:4326');
          let coords: any[] = [];
          if (geomTransformed.getType() === 'MultiPolygon') coords = (geomTransformed as any).getCoordinates()[0][0];
          else if (geomTransformed.getType() === 'Polygon') coords = (geomTransformed as any).getCoordinates()[0];
          if (!coords || coords.length === 0) throw new Error("Không thể đọc tọa độ.");
          const points: any[] = [];
          for (let i = 0; i < coords.length - 1; i++) {
              let [x, y] = [coords[i][0], coords[i][1]];
              try { const p = proj4('EPSG:4326', 'EPSG:9210', [x, y]); x = p[0]; y = p[1]; } catch(e) {}
              const [nextX_raw, nextY_raw] = [coords[i+1][0], coords[i+1][1]];
              let [nextX, nextY] = [nextX_raw, nextY_raw];
              try { const np = proj4('EPSG:4326', 'EPSG:9210', [nextX_raw, nextY_raw]); nextX = np[0]; nextY = np[1]; } catch(e) {}
              points.push({ id: i + 1, x, y, distanceNext: Math.sqrt(Math.pow(nextX - x, 2) + Math.pow(nextY - y, 2)).toFixed(2) });
          }
          setGeometryPoints(points);
          setTimeout(async () => {
              const element = printTemplateRef.current;
