const initDB = async () => {
    try {
        const client = await pool.connect();
        try {
            await client.query(`CREATE TABLE IF NOT EXISTS parcels (gid SERIAL PRIMARY KEY, sothua VARCHAR(50), sodoto VARCHAR(50), tenchu VARCHAR(255), diachi TEXT, loaidat VARCHAR(50), dientich NUMERIC, geometry GEOMETRY(Polygon, 4326), properties JSONB)`);
            await client.query(`CREATE TABLE IF NOT EXISTS users (id VARCHAR(50) PRIMARY KEY, email VARCHAR(100) UNIQUE NOT NULL, password_hash VARCHAR(255), name VARCHAR(100), role VARCHAR(20) DEFAULT 'VIEWER', branch_id VARCHAR(50))`);
            await client.query(`CREATE TABLE IF NOT EXISTS branches (id VARCHAR(50) PRIMARY KEY, code VARCHAR(20), name VARCHAR(100), address TEXT)`);
            await client.query(`CREATE TABLE IF NOT EXISTS system_settings (key VARCHAR(100) PRIMARY KEY, value TEXT, description TEXT, type VARCHAR(20) DEFAULT 'text')`);
            await seedDefaultSettings(client);
            await client.query(`CREATE TABLE IF NOT EXISTS system_logs (id SERIAL PRIMARY KEY, user_id VARCHAR(50), user_name VARCHAR(100), action VARCHAR(50), details TEXT, timestamp TIMESTAMP DEFAULT CURRENT_TIMESTAMP, branch_id VARCHAR(50))`);
            await client.query(`CREATE TABLE IF NOT EXISTS land_prices (land_type VARCHAR(50) PRIMARY KEY, base_price NUMERIC, description TEXT)`);
            await client.query(`CREATE TABLE IF NOT EXISTS wms_layers (id VARCHAR(50) PRIMARY KEY, name VARCHAR(100), url TEXT, layers VARCHAR(100), visible BOOLEAN DEFAULT true)`);
            await client.query(`CREATE TABLE IF NOT EXISTS role_permissions (role VARCHAR(20) PRIMARY KEY, permissions JSONB)`);
            await client.query(`CREATE TABLE IF NOT EXISTS spatial_tables_registry (table_name VARCHAR(100) PRIMARY KEY, display_name VARCHAR(100), created_at TIMESTAMP DEFAULT CURRENT_TIMESTAMP)`);
        } finally { client.release(); }
    } catch (err) {}
};
initDB();

app.get('/api/stats/dashboard', async (req, res) => {
    try {
        const tablesRes = await pool.query(`SELECT table_name FROM spatial_tables_registry`);
        let totalParcels = 0, totalArea = 0, valueByBranch = [];
        for (const t of tablesRes.rows) {
            const stats = await pool.query(`SELECT COUNT(*) as count, SUM(dientich) as area FROM "${t.table_name}"`);
            totalParcels += parseInt(stats.rows[0].count || 0);
            totalArea += parseFloat(stats.rows[0].area || 0);
            valueByBranch.push({ name: t.table_name, value: parseInt(stats.rows[0].count || 0) });
        }
        res.json({ totalParcels, totalArea, totalValue: totalArea * 2000000, valueByBranch, parcelsByType: [] });
    } catch (e) { res.status(500).json({ error: e.message }); }
});

