        await pool.query(`CREATE TABLE IF NOT EXISTS "${safeName}" (gid SERIAL PRIMARY KEY, sothua VARCHAR(50), sodoto VARCHAR(50), tenchu VARCHAR(255), diachi TEXT, loaidat VARCHAR(50), dientich NUMERIC, geometry GEOMETRY(Polygon, 4326), properties JSONB)`);
        await pool.query(`INSERT INTO spatial_tables_registry (table_name, display_name) VALUES ($1, $2) ON CONFLICT (table_name) DO NOTHING`, [safeName, displayName || safeName]);
        res.json({status:'ok'});
    } catch(e) { res.status(500).json({error:e.message}); }
