app.get('/api/:tableName', async (req, res) => {
    try {
        const { tableName } = req.params;
        const safeName = tableName.toLowerCase().replace(/[^a-z0-9_]/g, '');
        const { sothua, sodoto, tenchu } = req.query;
        let where = [], params = [], idx = 1;
        if (sothua) { where.push(`sothua = $${idx++}`); params.push(sothua); }
        if (sodoto) { where.push(`sodoto = $${idx++}`); params.push(sodoto); }
        if (tenchu) { where.push(`tenchu ILIKE $${idx++}`); params.push(`%${tenchu}%`); }
        const query = `SELECT gid, sothua, sodoto, tenchu, diachi, loaidat, dientich, ST_AsGeoJSON(geometry) as geojson FROM "${safeName}" ${where.length ? 'WHERE ' + where.join(' AND ') : ''} ORDER BY gid DESC LIMIT 50`;
        const r = await pool.query(query, params);
        res.json(r.rows.map(row => ({ ...row, geometry: JSON.parse(row.geojson || '{}') })));
    } catch(e) { res.status(500).json({error: e.message}); }
});

app.post('/api/:tableName', async (req, res) => {
    try {
        const { tableName } = req.params;
        const { sothua, sodoto, tenchu, diachi, loaidat, geometry } = req.body;
        const safeName = tableName.toLowerCase().replace(/[^a-z0-9_]/g, '');
        const geomVal = geometry ? `ST_SetSRID(ST_GeomFromGeoJSON('${JSON.stringify(geometry)}'), 4326)` : 'NULL';
        await pool.query(`INSERT INTO "${safeName}" (sothua, sodoto, tenchu, diachi, loaidat, geometry) VALUES ($1, $2, $3, $4, $5, ${geomVal})`, [sothua, sodoto, tenchu, diachi, loaidat]);
        res.json({status: 'ok'});
    } catch(e) { res.status(500).json({error: e.message}); }
});

