import express from 'express';
import cors from 'cors';
import pg from 'pg';
import multer from 'multer'; // Upload file handler
import shp from 'shpjs';     // Read Shapefile .zip
import dbConfig from './db_config.js';
import os from 'os';         // System info
import { spawn } from 'child_process'; // Execute shell commands for DB Backup/Restore

const { Pool } = pg;

const app = express();
const port = 3004;

app.enable('trust proxy');
const allowedOrigins = ['https://geo.gisvn.space', 'http://localhost:3003', 'http://localhost:5173'];
app.use(cors({ origin: allowedOrigins, credentials: true }));
app.use(express.json({ limit: '50mb' }));
app.use(express.urlencoded({ limit: '50mb', extended: true }));

const pool = new Pool(dbConfig);

// Helper function to map database rows to GeoJSON features
const mapRowToParcel = (row) => {
    return {
        gid: row.gid,
        sothua: row.sothua,
        sodoto: row.sodoto,
        tenchu: row.tenchu,
        diachi: row.diachi,
        loaidat: row.loaidat, // Land use purpose
        dientich: row.dientich,
        geometry: row.geojson ? JSON.parse(row.geojson) : null,
        properties: row.properties || {}
    };
};

// GET parcels for a table with filtering
app.get('/api/:tableName', async (req, res) => {
    try {
        const { tableName } = req.params;
        if (tableName === 'spatial-tables' || tableName === 'branches') return; // Skip system routes

        const { sothua, sodoto, tenchu } = req.query;
        let where = [], params = [], idx = 1;

        if (sothua) { where.push(`sothua = $${idx++}`); params.push(sothua); }
        if (sodoto) { where.push(`sodoto = $${idx++}`); params.push(sodoto); }
        if (tenchu) { where.push(`tenchu ILIKE $${idx++}`); params.push(`%${tenchu}%`); }

        const query = `
            SELECT gid, sothua, sodoto, tenchu, diachi, loaidat, dientich, ST_AsGeoJSON(geometry) as geojson, properties
            FROM "${tableName}"
            ${where.length ? 'WHERE ' + where.join(' AND ') : ''}
            ORDER BY gid DESC LIMIT 100
        `;
        const result = await pool.query(query, params);
        res.json(result.rows.map(mapRowToParcel));
    } catch (e) { res.status(500).json({ error: e.message }); }
});

// UPDATE parcel attributes
app.put('/api/:tableName/:gid', async (req, res) => {
    try {
        const { tableName, gid } = req.params;
        const { sothua, sodoto, tenchu, diachi, loaidat } = req.body;

        await pool.query(
            `UPDATE "${tableName}" SET sothua=$1, sodoto=$2, tenchu=$3, diachi=$4, loaidat=$5 WHERE gid=$6`,
            [sothua, sodoto, tenchu, diachi, loaidat, gid]
        );
        res.json({ status: 'ok' });
    } catch (e) { res.status(500).json({ error: e.message }); }
});

// [Rest of the server logic continues...]
app.listen(port, () => console.log(`🚀 Server running at port ${port}`));

