import express from 'express';
import cors from 'cors';
import pg from 'pg';
import multer from 'multer';
import dbConfig from './db_config.js';
import os from 'os';

const { Pool } = pg;
const app = express();
const port = 3004;

app.enable('trust proxy');
const allowedOrigins = ['https://geo.gisvn.space', 'http://localhost:3003', 'http://localhost:5173'];
app.use(cors({ origin: allowedOrigins, credentials: true }));
app.use(express.json({ limit: '50mb' }));

const pool = new Pool(dbConfig);

// --- AUTH API ---
app.post('/api/auth/login', async (req, res) => {
    const { email, password } = req.body;
    try {
        if (email === 'thai@gmail.com' && password === '123@') {
            return res.json({ id: 'u-1', email, name: 'Admin Thái', role: 'ADMIN', branchId: 'HEAD_OFFICE' });
        }
        res.status(401).json({ error: 'Sai tài khoản hoặc mật khẩu' });
    } catch (e) { res.status(500).json({ error: e.message }); }
});

// --- DASHBOARD STATS ---
app.get('/api/stats/dashboard', async (req, res) => {
    try {
        const tables = await pool.query(`SELECT table_name, display_name FROM spatial_tables_registry`);
        let totalParcels = 0, totalArea = 0, valueByBranch = [];
        for (const t of tables.rows) {
            const stats = await pool.query(`SELECT COUNT(*) as count, SUM(dientich) as area FROM "${t.table_name}"`);
            const count = parseInt(stats.rows[0].count || 0);
            totalParcels += count;
            totalArea += parseFloat(stats.rows[0].area || 0);
            valueByBranch.push({ name: t.display_name || t.table_name, value: count });
        }
        res.json({ totalParcels, totalArea, totalValue: totalArea * 2000000, valueByBranch, parcelsByType: [] });
    } catch (e) { res.status(500).json({ error: e.message }); }
});

// --- TABLE REGISTRY ---
app.get('/api/spatial-tables', async (req, res) => {
    try {
        const r = await pool.query(`SELECT table_name, display_name FROM spatial_tables_registry`);
        res.json(r.rows);
    } catch(e) { res.json([]); }
});

app.post('/api/spatial-tables', async (req, res) => {
    try {
        const { tableName, displayName } = req.body;
        const safeName = tableName.toLowerCase().replace(/[^a-z0-9_]/g, '');
        await pool.query(`CREATE TABLE IF NOT EXISTS "${safeName}" (gid SERIAL PRIMARY KEY, sothua VARCHAR(50), sodoto VARCHAR(50), tenchu VARCHAR(255), diachi TEXT, loaidat VARCHAR(50), dientich NUMERIC, geometry GEOMETRY(Polygon, 4326))`);
        await pool.query(`INSERT INTO spatial_tables_registry (table_name, display_name) VALUES ($1, $2) ON CONFLICT (table_name) DO NOTHING`, [safeName, displayName || safeName]);
        res.json({status:'ok'});
    } catch(e) { res.status(500).json({error:e.message}); }
});

// --- PARCEL CRUD ---
app.get('/api/:tableName', async (req, res) => {
    const { tableName } = req.params;
    if (['spatial-tables', 'branches', 'stats', 'wms-layers', 'settings'].includes(tableName)) return;
    try {
        const { sothua, sodoto, tenchu } = req.query;
        let where = [], params = [], idx = 1;
        if (sothua) { where.push(`sothua = $${idx++}`); params.push(sothua); }
        if (sodoto) { where.push(`sodoto = $${idx++}`); params.push(sodoto); }
        if (tenchu) { where.push(`tenchu ILIKE $${idx++}`); params.push(`%${tenchu}%`); }

        const query = `SELECT gid, sothua, sodoto, tenchu, diachi, loaidat, dientich, ST_AsGeoJSON(geometry) as geojson FROM "${tableName}" ${where.length ? 'WHERE ' + where.join(' AND ') : ''} ORDER BY gid DESC LIMIT 100`;
        const result = await pool.query(query, params);
        res.json(result.rows.map(r => ({ ...r, geometry: JSON.parse(r.geojson || '{}') })));
    } catch (e) { res.status(500).json({ error: e.message }); }
});

app.put('/api/:tableName/:gid', async (req, res) => {
    try {
        const { tableName, gid } = req.params;
        const { sothua, sodoto, tenchu, diachi, loaidat } = req.body;
        await pool.query(
            `UPDATE "${tableName}" SET sothua=$1, sodoto=$2, tenchu=$3, diachi=$4, loaidat=$5 WHERE gid=$6`,
            [sothua, sodoto, tenchu, diachi, loaidat, gid]
        );
        res.json({ status: 'ok' });
    } catch (e) { res.status(500).json({ error: e.message }); }
});

// --- SYSTEM ---
app.get('/api/wms-layers', async (req, res) => {
    try {
        const r = await pool.query(`SELECT * FROM wms_layers`);
        res.json(r.rows);
    } catch(e) { res.json([]); }
});

app.get('/api/settings', async (req, res) => {
    try {
        const r = await pool.query(`SELECT * FROM system_settings`);
        res.json(r.rows);
    } catch(e) { res.json([]); }
});

app.get('/api/branches', async (req, res) => {
    try {
        const r = await pool.query(`SELECT * FROM branches`);
        res.json(r.rows);
    } catch(e) { res.json([]); }
});

app.get('/api/proxy/forward', async (req, res) => {
    try {
        const { url } = req.query;
        const response = await fetch(url);
        const data = await response.json();
        res.json(data);
    } catch (e) { res.status(500).json({ error: e.message }); }
});

app.listen(port, () => console.log(`🚀 GIS Server running at http://localhost:${port}`));

import React, { useEffect, useRef, useState } from 'react';
import { User, LandParcel, UserRole, WMSLayerConfig } from '../types';
import { gisService, API_URL } from '../services/mockBackend';
