// --- VN-2000 CONFIG ---
proj4.defs("EPSG:9210", "+proj=tmerc +lat_0=0 +lon_0=105.75 +k=0.9999 +x_0=500000 +y_0=0 +ellps=WGS84 +towgs84=-191.90441429,-39.30318279,-111.45032835,0.00928836,0.01975479,-0.00427372,0.252906278 +units=m +no_defs");

interface MapPageProps {
  user: User | null;
  systemSettings?: Record<string, string>;
}

const MapPage: React.FC<MapPageProps> = ({ user, systemSettings }) => {
  const mapElement = useRef<HTMLDivElement>(null);
  const mapInstance = useRef<Map | null>(null);
  const popupElement = useRef<HTMLDivElement>(null);
  const popupOverlay = useRef<Overlay | null>(null);

  // Layer Refs
  const osmLayer = useRef<TileLayer<OSM> | null>(null);
  const googleLayer = useRef<TileLayer<XYZ> | null>(null);
  const vietbandoLayer = useRef<TileLayer<XYZ> | null>(null);
  const wmsLayerGroup = useRef<LayerGroup | null>(null);
  const highlightLayer = useRef<VectorLayer<VectorSource> | null>(null);

  // State
  const [selectedParcel, setSelectedParcel] = useState<LandParcel | null>(null);
  const [isPopupEditing, setIsPopupEditing] = useState(false);
  const [formData, setFormData] = useState<any>({});

  // UI State
  const [availableLayers, setAvailableLayers] = useState<WMSLayerConfig[]>([]);
  const [visibleLayerIds, setVisibleLayerIds] = useState<string[]>([]);
  const [activeLayerId, setActiveLayerId] = useState<string | null>(null);

  const [isSaving, setIsSaving] = useState(false);
  const [isFetchingInfo, setIsFetchingInfo] = useState(false);
  const [isGeneratingPDF, setIsGeneratingPDF] = useState(false);
  const [isSearchOpen, setIsSearchOpen] = useState(false);

  useEffect(() => {
    const initData = async () => {
      try {
        const layers = await gisService.getLayers();
        setAvailableLayers(layers);
        const defaults = layers.filter(l => l.visible).map(l => l.id);
        setVisibleLayerIds(defaults);
        if (layers.length > 0) setActiveLayerId(layers[0].id);
      } catch (e) { console.error("Load layers error", e); }
    };
    initData();
  }, []);

  useEffect(() => {
    if (!mapElement.current || mapInstance.current) return;

    // 1. Initialize Layers
    osmLayer.current = new TileLayer({ source: new OSM(), visible: true });
    googleLayer.current = new TileLayer({ 
      source: new XYZ({ url: 'https://mt1.google.com/vt/lyrs=y&x={x}&y={y}&z={z}' }), 
      visible: false 
    });
    vietbandoLayer.current = new TileLayer({ 
      source: new XYZ({ url: `${API_URL}/api/proxy/vietbando?z={z}&x={x}&y={y}` }), 
      visible: false 
    });
    wmsLayerGroup.current = new LayerGroup({ layers: [] });

    highlightLayer.current = new VectorLayer({
      source: new VectorSource(),
      style: new Style({
        stroke: new Stroke({ color: '#ef4444', width: 3 }),
        fill: new Fill({ color: 'rgba(239, 68, 68, 0.1)' })
      }),
      zIndex: 100
    });

    // 2. Initialize Map
    const map = new Map({
      target: mapElement.current,
      layers: [
        osmLayer.current, 
        googleLayer.current, 
        vietbandoLayer.current, 
        wmsLayerGroup.current, 
        highlightLayer.current
      ],
      view: new View({ center: fromLonLat([106.619, 11.284]), zoom: 13 }),
      controls: defaultControls({ attribution: false })
    });

    // 3. Initialize Popup
    popupOverlay.current = new Overlay({
      element: popupElement.current!,
      autoPan: { animation: { duration: 250 } },
      positioning: 'bottom-center',
      offset: [0, -10]
    });
    map.addOverlay(popupOverlay.current);

    // 4. Click Handler
    map.on('singleclick', async (evt) => {
      await identifyFeature(evt.coordinate);
    });

    mapInstance.current = map;
    return () => { map.setTarget(undefined); mapInstance.current = null; };
  }, []);

  useEffect(() => {
    if (!wmsLayerGroup.current) return;
    wmsLayerGroup.current.getLayers().clear();
    availableLayers.forEach(config => {
      const isActive = config.id === activeLayerId;
      if (visibleLayerIds.includes(config.id)) {
        const layer = new TileLayer({
          source: new TileWMS({
            url: config.url,
            params: { 'LAYERS': config.layers, 'TILED': true, 'TRANSPARENT': true },
            serverType: 'geoserver'
          }),
          properties: { config, isActive },
          zIndex: isActive ? 100 : 10
        });
        wmsLayerGroup.current!.getLayers().push(layer);
      }
    });
  }, [availableLayers, visibleLayerIds, activeLayerId]);

  const identifyFeature = async (coordinate: number[]) => {
    if (!mapInstance.current || !wmsLayerGroup.current) return;
    setIsPopupEditing(false);

    const layers = wmsLayerGroup.current.getLayers().getArray();
    let targetLayer = layers.find((l:any) => l.get('isActive') === true) || layers[layers.length - 1];

    if (!targetLayer) {
      setSelectedParcel(null);
      popupOverlay.current?.setPosition(undefined);
      highlightLayer.current?.getSource()?.clear();
      return;
    }

    const source = (targetLayer as TileLayer<TileWMS>).getSource();
    const url = source?.getFeatureInfoUrl(
      coordinate,
      mapInstance.current.getView().getResolution()!,
      mapInstance.current.getView().getProjection(),
      { 'INFO_FORMAT': 'application/json', 'FEATURE_COUNT': 1 }
    );

    if (url) {
      setIsFetchingInfo(true);
      try {
        const res = await fetch(`${API_URL}/api/proxy/forward?url=${encodeURIComponent(url)}`);
        const data = await res.json();
        if (data.features?.length > 0) {
          const feature = data.features[0];
          const props = feature.properties;

          const mappedParcel: LandParcel = {
            id: feature.id || String(Date.now()),
            geometry: feature.geometry,
            properties: {
              gid: props.gid || feature.id?.split('.').pop(),
              ownerName: props.tenchu || props.owner || 'Chưa cập nhật',
              landType: props.loaidat || props.kh || props.mdsd || 'Chưa xác định',
              area: Number(props.dientich || props.area || 0),
              so_to: props.sodoto || props.so_to,
              so_thua: props.sothua || props.so_thua,
              address: props.diachi || props.address,
              tableName: (targetLayer.get('config') as WMSLayerConfig).layers.split(':').pop() || 'parcels',
              tableDisplayName: (targetLayer.get('config') as WMSLayerConfig).name,
              pricePerM2: props.pricePerM2 || 0,
              totalValue: props.totalValue || 0,
              planningStatus: props.planningStatus || 'Safe',
              branchId: props.branchId || (user?.branchId || 'default')
            }
          };

          const olFeature = (new GeoJSON()).readFeature(feature);
          highlightLayer.current?.getSource()?.clear();
          // Fixed error: Argument of type 'Feature<Geometry> | Feature<Geometry>[]' is not assignable to parameter of type 'Feature<Geometry>'.
          // Use instanceof check to satisfy TypeScript that we have a single Feature instance.
          if (olFeature instanceof Feature) {
            highlightLayer.current?.getSource()?.addFeature(olFeature);
          }

          setSelectedParcel(mappedParcel);
          setFormData(mappedParcel.properties);
          popupOverlay.current?.setPosition(coordinate);
        } else {
          setSelectedParcel(null);
          popupOverlay.current?.setPosition(undefined);
          highlightLayer.current?.getSource()?.clear();
        }
      } catch (e) { console.error("Identify error", e); }
      finally { setIsFetchingInfo(true); setIsFetchingInfo(false); }
    }
  };

  const handleSaveAttributes = async () => {
    if (!formData.tableName || !formData.gid) return;
    setIsSaving(true);
    try {
      await parcelApi.update(formData.tableName, formData.gid, {
        sodoto: formData.so_to,
        sothua: formData.so_thua,
        tenchu: formData.ownerName,
        diachi: formData.address,
        loaidat: formData.landType // Lưu mã mục đích sử dụng đất
      } as any);
      alert("Đã cập nhật mục đích sử dụng và thông tin thửa đất thành công!");
      setIsPopupEditing(false);
      // Optional: Refresh WMS by adding random param
      const layers = wmsLayerGroup.current?.getLayers().getArray();
      layers?.forEach((l: any) => {
          const source = l.getSource();
          if (source instanceof TileWMS) {
              source.updateParams({ 't': Date.now() });
          }
      });
    } catch (err: any) {
      alert("Lỗi lưu dữ liệu: " + err.message);
    } finally { setIsSaving(false); }
  };

  return (
    <div className="relative w-full h-full bg-gray-100">
      <div ref={mapElement} className="w-full h-full z-0" />

      {/* POPUP CONTAINER */}
      <div ref={popupElement} className="ol-popup min-w-[320px]">
        {selectedParcel && (
          <div className="flex flex-col w-full bg-white rounded-xl overflow-hidden shadow-2xl border border-gray-300 font-sans">
            <div className="bg-gradient-to-r from-blue-700 to-blue-600 text-white p-3 flex justify-between items-start">
              <div>
                <h3 className="font-bold flex items-center gap-2 text-base">
                  <Info size={18} /> {isPopupEditing ? 'Chỉnh sửa thửa đất' : 'Thông tin thửa đất'}
                </h3>
                <p className="text-[10px] text-blue-100 mt-1 opacity-80">Nguồn: {formData.tableDisplayName}</p>
              </div>
              <button onClick={() => { setSelectedParcel(null); setIsPopupEditing(false); popupOverlay.current?.setPosition(undefined); }}><X size={18} /></button>
            </div>

            <div className="p-4 space-y-4">
              {!isPopupEditing ? (
                <>
                  <div className="grid grid-cols-2 gap-3">
                    <div className="bg-gray-50 border p-2 rounded text-center">
                      <label className="text-[9px] font-bold text-gray-400 uppercase">Tờ</label>
                      <div className="text-xl font-black text-blue-600">{formData.so_to || '?'}</div>
                    </div>
                    <div className="bg-gray-50 border p-2 rounded text-center">
                      <label className="text-[9px] font-bold text-gray-400 uppercase">Thửa</label>
                      <div className="text-xl font-black text-blue-600">{formData.so_thua || '?'}</div>
                    </div>
                  </div>
                  <div className="space-y-2">
                    <div className="flex items-center gap-2">
                      <UserIcon size={14} className="text-gray-400" />
                      <span className="text-sm font-bold">{formData.ownerName}</span>
                    </div>
                    <div className="flex items-center gap-2">
                      <Tag size={14} className="text-purple-500" />
                      <span className="text-sm font-medium bg-purple-50 text-purple-700 px-2 py-0.5 rounded border border-purple-100">
                        Loại đất: {formData.landType}
                      </span>
                    </div>
                    <div className="flex items-start gap-2">
                      <MapPin size={14} className="text-gray-400 mt-1" />
                      <span className="text-xs text-gray-600 leading-tight">{formData.address || 'Chưa cập nhật'}</span>
                    </div>
                  </div>
                  <div className="flex gap-2 pt-2 border-t">
                    <button onClick={() => {}} className="flex-1 bg-blue-600 text-white py-2 rounded text-xs font-bold flex justify-center items-center gap-2">
                      <Printer size={14} /> Trích lục
                    </button>
                    {user && user.role !== UserRole.VIEWER && (
                      <button onClick={() => setIsPopupEditing(true)} className="bg-gray-100 text-gray-700 p-2 rounded hover:bg-gray-200">
                        <Edit size={16} />
