                  <div className="space-y-1">
                    <label className="text-[10px] font-bold text-blue-600 uppercase">Mục đích sử dụng (Mã loại đất)</label>
                    <input className="w-full border-2 border-blue-200 rounded p-1.5 text-sm font-bold text-blue-700" placeholder="VD: ODT, ONT, CLN..." value={formData.landType||''} onChange={e=>setFormData({...formData, landType: e.target.value})} />
                  </div>
                  <textarea className="w-full border rounded p-1.5 text-sm h-12" placeholder="Địa chỉ" value={formData.address||''} onChange={e=>setFormData({...formData, address: e.target.value})} />
                  <div className="flex gap-2 pt-2">
                    <button onClick={() => setIsPopupEditing(false)} className="flex-1 bg-gray-100 py-2 rounded text-xs font-bold">Hủy</button>
                    <button onClick={handleSaveAttributes} disabled={isSaving} className="flex-1 bg-green-600 text-white py-2 rounded text-xs font-bold flex justify-center items-center gap-2">
                      {isSaving ? <RefreshCw size={14} className="animate-spin"/> : <Save size={14}/>} Lưu
                    </button>
                  </div>
                </div>
              )}
            </div>
          </div>
        )}
      </div>

      {/* OVERLAY CONTROLS */}
      <div className="absolute top-4 left-16 z-[400]">
        <button onClick={() => setIsSearchOpen(!isSearchOpen)} className="p-3 bg-white rounded-lg shadow-lg hover:bg-gray-50">
          <Search size={24} />
        </button>
      </div>

      <div className="absolute bottom-24 right-4 z-[400]">
        <button onClick={() => {}} className="p-3 bg-white rounded-lg shadow-lg">
          <Crosshair size={24} />
        </button>
      </div>
    </div>
  );
};

export default MapPage;
